// NORMAL DISTRIBUTION
// ══════════════════════════════════════════════════════════════════════════
{
  const S = ["normal-distribution"];
  const normalPdf = (mu: number, sigma: number) => (x: number) =>
    (1 / (sigma * Math.sqrt(2 * Math.PI))) *
    Math.exp(-0.5 * Math.pow((x - mu) / sigma, 2));
  const mcq: MCQ[] = [
    { content: "If $X \\sim N(\\mu, \\sigma^2)$, the standardised variable $Z$ is given by:", optionA: "$Z = X - \\mu$", optionB: "$Z = \\dfrac{X - \\mu}{\\sigma}$", optionC: "$Z = \\dfrac{\\mu - X}{\\sigma}$", optionD: "$Z = \\sigma(X - \\mu)$", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Standardisation formula.\n\n$$Z = \\dfrac{X - \\mu}{\\sigma}.$$\n\n**Answer: B**", subtopicSlugs: S },
    { content: "For a standard normal distribution, $\\Pr(Z < 0)$ equals:", optionA: "$0$", optionB: "$0.25$", optionC: "$0.5$", optionD: "$1$", correctOption: "C", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** By symmetry of the standard normal about $0$, $\\Pr(Z < 0) = 0.5$.\n\n**Answer: C**", subtopicSlugs: S },
    { content: "If $X \\sim N(50, 100)$, then the standard deviation is:", optionA: "$10$", optionB: "$50$", optionC: "$100$", optionD: "$1000$", correctOption: "A", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Variance $\\sigma^2 = 100$, so $\\sigma = 10$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "By the empirical (68-95-99.7) rule, approximately what percentage of $N(\\mu, \\sigma^2)$ values lie within $1\\sigma$ of $\\mu$?", optionA: "$50\\%$", optionB: "$68\\%$", optionC: "$95\\%$", optionD: "$99.7\\%$", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** The empirical rule: about $68\\%$ lies within $1\\sigma$, $95\\%$ within $2\\sigma$, $99.7\\%$ within $3\\sigma$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "If $X \\sim N(20, 16)$, then $\\Pr(X > 20)$ equals:", optionA: "$0.25$", optionB: "$0.5$", optionC: "$0.68$", optionD: "$0.95$", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** By symmetry about the mean $\\mu = 20$, $\\Pr(X > 20) = 0.5$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "For $X \\sim N(100, 25)$, approximately what percentage lies in $[95, 105]$?", optionA: "$50\\%$", optionB: "$68\\%$", optionC: "$95\\%$", optionD: "$99.7\\%$", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $\\sigma = 5$, so $[95, 105]$ corresponds to $\\mu \\pm 1\\sigma$, i.e. about $68\\%$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: `The pdf of a standard normal distribution is shown.\n\n${graphImage(normalPdf(0, 1), { xMin: -4, xMax: 4, yMin: 0, yMax: 0.45 }, "Standard normal pdf")}\n\nThe total area under the curve equals:`, optionA: "$0$", optionB: "$0.5$", optionC: "$1$", optionD: "$\\pi$", correctOption: "C", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Every probability density function integrates to $1$.\n\n**Answer: C**", subtopicSlugs: S },
    { content: `The curves $N(0, 1)$ (blue) and a second normal distribution $N(2, 4)$ (shifted, wider) belong to which parameterisation?\n\n${graphImage(normalPdf(2, 2), { xMin: -4, xMax: 8, yMin: 0, yMax: 0.25 }, "N(2, 4) pdf")}\n\nFor $N(2, 4)$, the standard deviation is:`, optionA: "$1$", optionB: "$2$", optionC: "$4$", optionD: "$16$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Variance is $4$, so $\\sigma = \\sqrt{4} = 2$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "Given $\\Pr(Z < 1) \\approx 0.8413$, the value of $\\Pr(Z > 1)$ is approximately:", optionA: "$0.1587$", optionB: "$0.3413$", optionC: "$0.5000$", optionD: "$0.8413$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $\\Pr(Z > 1) = 1 - \\Pr(Z < 1) = 1 - 0.8413 = 0.1587$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "If $X \\sim N(60, 100)$, the standardised value for $X = 75$ is:", optionA: "$0.75$", optionB: "$1.5$", optionC: "$15$", optionD: "$75$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $\\sigma = 10$. Compute $Z$.\n\n$$Z = \\tfrac{75 - 60}{10} = 1.5.$$\n\n**Answer: B**", subtopicSlugs: S },
    { content: "Given $\\Pr(Z < 1.96) \\approx 0.975$, $\\Pr(-1.96 < Z < 1.96)$ is approximately:", optionA: "$0.025$", optionB: "$0.475$", optionC: "$0.950$", optionD: "$0.975$", correctOption: "C", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** By symmetry, $\\Pr(-1.96 < Z < 1.96) = 2 \\cdot 0.975 - 1 = 0.95$.\n\n**Answer: C**", subtopicSlugs: S },
    { content: "For $X \\sim N(80, 36)$, $\\Pr(X < 74)$ equals:", optionA: "$\\Pr(Z < -1)$", optionB: "$\\Pr(Z < 1)$", optionC: "$\\Pr(Z < -0.5)$", optionD: "$\\Pr(Z < 0.5)$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $\\sigma = 6$. Standardise.\n\n$$Z = \\tfrac{74 - 80}{6} = -1.$$\n\n**Answer: A**", subtopicSlugs: S },
    { content: `For a normal distribution, the following table gives some probabilities.\n\n| $z$ | $\\Pr(Z \\leq z)$ |\n|---|---|\n| $1.0$ | $0.8413$ |\n| $1.5$ | $0.9332$ |\n| $2.0$ | $0.9772$ |\n\nThe value of $\\Pr(1 \\leq Z \\leq 2)$ is:`, optionA: "$0.1359$", optionB: "$0.1587$", optionC: "$0.2045$", optionD: "$0.8185$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Subtract.\n\n$$\\Pr(1 \\leq Z \\leq 2) = 0.9772 - 0.8413 = 0.1359.$$\n\n**Answer: A**", subtopicSlugs: S },
    { content: "If $X \\sim N(50, 25)$ and $\\Pr(X > a) = 0.025$, then $a$ (using $z = 1.96$) is closest to:", optionA: "$59.8$", optionB: "$60.0$", optionC: "$61.96$", optionD: "$52.0$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $\\sigma = 5$. $a = 50 + 1.96 \\cdot 5 = 59.8$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "For $X \\sim N(10, 4)$, $\\Pr(X < 10) + \\Pr(X > 12)$ using $z = 1$ gives:", optionA: "$0.3174$", optionB: "$0.6587$", optionC: "$0.8413$", optionD: "$0.9772$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $\\sigma = 2$. $\\Pr(X < 10) = 0.5$ and $\\Pr(X > 12) = \\Pr(Z > 1) = 0.1587$.\n\n$$0.5 + 0.1587 = 0.6587.$$\n\n**Answer: B**", subtopicSlugs: S },
    { content: `A normal distribution $N(\\mu, \\sigma^2)$ pdf is shown with vertical lines at $\\mu - \\sigma$ and $\\mu + \\sigma$.\n\n${graphImage(normalPdf(0, 1), { xMin: -4, xMax: 4, yMin: 0, yMax: 0.45 }, "N(0,1) with ±1 sigma marks")}\n\nThe shaded central region (between $\\mu - \\sigma$ and $\\mu + \\sigma$) has area approximately:`, optionA: "$0.34$", optionB: "$0.50$", optionC: "$0.68$", optionD: "$0.95$", correctOption: "C", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** By the empirical rule, approximately $68\\%$ of data lies within $\\pm 1\\sigma$.\n\n**Answer: C**", subtopicSlugs: S },
    { content: "If $X \\sim N(\\mu, \\sigma^2)$ and $\\Pr(X < 40) = 0.1587$ and $\\Pr(X < 60) = 0.8413$, then $\\mu$ equals:", optionA: "$40$", optionB: "$50$", optionC: "$55$", optionD: "$60$", correctOption: "B", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $\\Pr(X < 40)$ and $\\Pr(X < 60)$ are symmetric about $0.5$ (both correspond to $|z| = 1$), so $\\mu$ is the midpoint.\n\n$$\\mu = \\tfrac{40 + 60}{2} = 50.$$\n\n**Answer: B**", subtopicSlugs: S },
    { content: "In the previous scenario, the standard deviation $\\sigma$ equals:", optionA: "$5$", optionB: "$10$", optionC: "$15$", optionD: "$20$", correctOption: "B", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** Since $\\Pr(X < 40) = \\Pr(Z < -1) = 0.1587$, we have $\\mu - \\sigma = 40$, so $\\sigma = 50 - 40 = 10$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "The heights of students are $N(170, 64)$ cm. The probability a student is taller than $186$ cm (using $z = 2$) is approximately:", optionA: "$0.0228$", optionB: "$0.1587$", optionC: "$0.8413$", optionD: "$0.9772$", correctOption: "A", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $\\sigma = 8$. $Z = \\tfrac{186 - 170}{8} = 2$.\n\n$$\\Pr(Z > 2) = 1 - 0.9772 = 0.0228.$$\n\n**Answer: A**", subtopicSlugs: S },
    { content: "If $X \\sim N(\\mu, \\sigma^2)$ and $\\Pr(X < k) = 0.0228$, using $z = -2$ we have:", optionA: "$k = \\mu - 2\\sigma$", optionB: "$k = \\mu + 2\\sigma$", optionC: "$k = \\mu - \\sigma$", optionD: "$k = \\mu + \\sigma$", correctOption: "A", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $\\Pr(Z < -2) = 0.0228$, so $\\tfrac{k - \\mu}{\\sigma} = -2$, giving $k = \\mu - 2\\sigma$.\n\n**Answer: A**", subtopicSlugs: S },
  ];
  const shortAnswer: FR[] = [
    { content: "Let $X \\sim N(50, 25)$. Find the standardised value of $X = 60$.", marks: 2, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Identify $\\sigma = 5$.\n\n**Step 2 (1 mark):** Compute.\n\n$$Z = \\tfrac{60 - 50}{5} = 2.$$", subtopicSlugs: S },
    { content: "Let $X \\sim N(100, 400)$.\n\na. State $\\sigma$. (1 mark)\n\nb. Find the standardised value of $X = 140$. (1 mark)", marks: 2, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $\\sigma = \\sqrt{400} = 20$.\n\n**Step 2 (1 mark):** $Z = \\tfrac{140 - 100}{20} = 2$.", subtopicSlugs: S },
    { content: "Using the empirical rule, estimate the probability that a $N(\\mu, \\sigma^2)$ random variable lies between $\\mu - 2\\sigma$ and $\\mu + 2\\sigma$.", marks: 2, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Identify the relevant range as $\\pm 2\\sigma$.\n\n**Step 2 (1 mark):** By the empirical rule, approximately $95\\%$ lies in this range.", subtopicSlugs: S },
    { content: "Given $\\Pr(Z < 1.5) = 0.9332$, find:\n\na. $\\Pr(Z > 1.5)$. (1 mark)\n\nb. $\\Pr(-1.5 < Z < 1.5)$. (2 marks)", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $\\Pr(Z > 1.5) = 1 - 0.9332 = 0.0668$.\n\n**Step 2 (1 mark):** By symmetry, $\\Pr(Z < -1.5) = 0.0668$.\n\n**Step 3 (1 mark):** $\\Pr(-1.5 < Z < 1.5) = 1 - 2(0.0668) = 0.8664$.", subtopicSlugs: S },
    { content: "The weights (kg) of apples are normally distributed with mean $0.15$ and standard deviation $0.02$. Find $\\Pr(X > 0.19)$ using $\\Pr(Z < 2) = 0.9772$.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Standardise.\n\n$$Z = \\tfrac{0.19 - 0.15}{0.02} = 2.$$\n\n**Step 2 (1 mark):** $\\Pr(Z > 2) = 1 - 0.9772$.\n\n**Step 3 (1 mark):** $\\Pr(X > 0.19) = 0.0228$.", subtopicSlugs: S },
    { content: "For $X \\sim N(70, 81)$, use $z = 1$ to find $\\Pr(61 \\leq X \\leq 79)$.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $\\sigma = 9$. The interval is $\\mu \\pm 1\\sigma$.\n\n**Step 2 (1 mark):** By the empirical rule, $\\Pr(\\mu - \\sigma \\leq X \\leq \\mu + \\sigma) \\approx 0.68$.\n\n**Step 3 (1 mark):** So $\\Pr(61 \\leq X \\leq 79) \\approx 0.68$.", subtopicSlugs: S },
    { content: "IQ scores follow $N(100, 225)$. A person has IQ $130$.\n\na. Find their $z$-score. (1 mark)\n\nb. Using $\\Pr(Z < 2) = 0.9772$, find the percentile. (2 marks)", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $\\sigma = 15$. $Z = \\tfrac{130 - 100}{15} = 2$.\n\n**Step 2 (1 mark):** $\\Pr(X < 130) = \\Pr(Z < 2) = 0.9772$.\n\n**Step 3 (1 mark):** Percentile is $97.72\\%$.", subtopicSlugs: S },
    { content: "Exam scores are $N(65, 100)$. Given $\\Pr(Z < 1) = 0.8413$, find the probability a score exceeds $75$.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $\\sigma = 10$. Standardise.\n\n$$Z = \\tfrac{75 - 65}{10} = 1.$$\n\n**Step 2 (1 mark):** $\\Pr(Z > 1) = 1 - 0.8413$.\n\n**Step 3 (1 mark):** $\\Pr(X > 75) = 0.1587$.", subtopicSlugs: S },
    { content: "If $X \\sim N(\\mu, \\sigma^2)$ and $\\Pr(X < 12) = 0.8413$ and $\\Pr(X < 8) = 0.1587$, find $\\mu$ and $\\sigma$.", marks: 4, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $\\Pr(X < 12) = 0.8413 \\Rightarrow z = 1$, so $\\mu + \\sigma = 12$.\n\n**Step 2 (1 mark):** $\\Pr(X < 8) = 0.1587 \\Rightarrow z = -1$, so $\\mu - \\sigma = 8$.\n\n**Step 3 (1 mark):** Add: $2\\mu = 20 \\Rightarrow \\mu = 10$.\n\n**Step 4 (1 mark):** Subtract: $2\\sigma = 4 \\Rightarrow \\sigma = 2$.", subtopicSlugs: S },
    { content: "For $X \\sim N(50, 64)$ and $\\Pr(Z < 1.5) = 0.9332$, find $\\Pr(42 < X < 62)$.", marks: 4, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $\\sigma = 8$. Standardise endpoints.\n\n$$Z_1 = \\tfrac{42 - 50}{8} = -1, \\quad Z_2 = \\tfrac{62 - 50}{8} = 1.5.$$\n\n**Step 2 (1 mark):** $\\Pr(Z < 1.5) = 0.9332$ and $\\Pr(Z < -1) = 1 - 0.8413 = 0.1587$.\n\n**Step 3 (1 mark):** Subtract.\n\n$$\\Pr(42 < X < 62) = 0.9332 - 0.1587.$$\n\n**Step 4 (1 mark):** Evaluate.\n\n$$= 0.7745.$$", subtopicSlugs: S },
  ];
  const extendedResponse: FR[] = [
    { content: "The heights $H$ (cm) of adult men in a city are normally distributed with $\\mu = 178$ and $\\sigma = 7$.\n\n**a.** Find $\\Pr(H > 185)$, using $\\Pr(Z < 1) = 0.8413$. (2 marks)\n\n**b.** Find $\\Pr(164 < H < 192)$, using $\\Pr(Z < 2) = 0.9772$. (3 marks)\n\n**c.** Find the height exceeded by only $2.5\\%$ of men, using $z = 1.96$. (2 marks)\n\n**d.** Approximately what percentage of men are shorter than $171$ cm? (2 marks)\n\n**e.** If a man's height is $165$ cm, give his $z$-score and interpret. (2 marks)", marks: 11, difficulty: "HARD", solutionContent: "**a. (2 marks)**\n\n*Step 1 (1 mark):* Standardise.\n\n$$Z = \\tfrac{185 - 178}{7} = 1.$$\n\n*Step 2 (1 mark):* $\\Pr(Z > 1) = 1 - 0.8413 = 0.1587$.\n\n**b. (3 marks)**\n\n*Step 1 (1 mark):* Standardise both endpoints.\n\n$$Z_1 = \\tfrac{164 - 178}{7} = -2, \\quad Z_2 = \\tfrac{192 - 178}{7} = 2.$$\n\n*Step 2 (1 mark):* $\\Pr(-2 < Z < 2) = 2(0.9772) - 1$.\n\n*Step 3 (1 mark):* $= 0.9544$.\n\n**c. (2 marks)**\n\n*Step 1 (1 mark):* $\\Pr(Z > 1.96) = 0.025$.\n\n*Step 2 (1 mark):* Height = $178 + 1.96 \\cdot 7 = 191.72$ cm.\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* $Z = \\tfrac{171 - 178}{7} = -1$.\n\n*Step 2 (1 mark):* $\\Pr(Z < -1) = 0.1587 \\approx 15.87\\%$.\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* $Z = \\tfrac{165 - 178}{7} \\approx -1.86$.\n\n*Step 2 (1 mark):* The man is about $1.86$ standard deviations below the mean (shorter than average).", subtopicSlugs: S },
    { content: "The time $T$ (minutes) students spend on a test is $N(40, 25)$.\n\n**a.** Find $\\Pr(T < 35)$, using $\\Pr(Z < 1) = 0.8413$. (2 marks)\n\n**b.** Find $\\Pr(30 < T < 50)$, using $\\Pr(Z < 2) = 0.9772$. (3 marks)\n\n**c.** A random sample of $100$ students is taken. Approximately how many would be expected to spend more than $45$ minutes? (2 marks)\n\n**d.** The teacher wants to set a time limit such that only $5\\%$ of students need more time. Using $z = 1.645$, find the limit. (2 marks)", marks: 9, difficulty: "HARD", solutionContent: "**a. (2 marks)**\n\n*Step 1 (1 mark):* $\\sigma = 5$. $Z = \\tfrac{35 - 40}{5} = -1$.\n\n*Step 2 (1 mark):* $\\Pr(Z < -1) = 1 - 0.8413 = 0.1587$.\n\n**b. (3 marks)**\n\n*Step 1 (1 mark):* $Z_1 = \\tfrac{30 - 40}{5} = -2$ and $Z_2 = \\tfrac{50 - 40}{5} = 2$.\n\n*Step 2 (1 mark):* $\\Pr(-2 < Z < 2) = 2(0.9772) - 1$.\n\n*Step 3 (1 mark):* $= 0.9544$.\n\n**c. (2 marks)**\n\n*Step 1 (1 mark):* $Z = \\tfrac{45 - 40}{5} = 1$. $\\Pr(T > 45) = 0.1587$.\n\n*Step 2 (1 mark):* Expected count: $100 \\cdot 0.1587 \\approx 16$ students.\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* $\\Pr(Z > 1.645) = 0.05$.\n\n*Step 2 (1 mark):* Limit $= 40 + 1.645 \\cdot 5 = 48.225$ minutes.", subtopicSlugs: S },
    { content: "Weekly sales $S$ (thousands of dollars) of a store are $N(20, 9)$.\n\n**a.** Find $\\Pr(S > 23)$, using $\\Pr(Z < 1) = 0.8413$. (2 marks)\n\n**b.** Find $\\Pr(14 < S < 26)$, using $\\Pr(Z < 2) = 0.9772$. (3 marks)\n\n**c.** Find the median weekly sales. (1 mark)\n\n**d.** Find the value $k$ such that $\\Pr(S > k) = 0.025$, using $z = 1.96$. (2 marks)\n\n**e.** In a $52$-week year, estimate the number of weeks with sales below $14$. (2 marks)\n\n**f.** If in one week sales are $17$, compute the $z$-score and interpret. (2 marks)", marks: 12, difficulty: "HARD", solutionContent: "**a. (2 marks)**\n\n*Step 1 (1 mark):* $\\sigma = 3$. $Z = \\tfrac{23 - 20}{3} = 1$.\n\n*Step 2 (1 mark):* $\\Pr(Z > 1) = 0.1587$.\n\n**b. (3 marks)**\n\n*Step 1 (1 mark):* $Z_1 = \\tfrac{14 - 20}{3} = -2$ and $Z_2 = \\tfrac{26 - 20}{3} = 2$.\n\n*Step 2 (1 mark):* $\\Pr(-2 < Z < 2) = 2(0.9772) - 1$.\n\n*Step 3 (1 mark):* $= 0.9544$.\n\n**c. (1 mark)**\n\n*Step 1 (1 mark):* For a normal distribution, median $=$ mean $= 20$ (i.e. \\$20{,}000).\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* $\\Pr(Z > 1.96) = 0.025$.\n\n*Step 2 (1 mark):* $k = 20 + 1.96 \\cdot 3 = 25.88$ (thousand dollars).\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* $\\Pr(S < 14) = \\Pr(Z < -2) = 0.0228$.\n\n*Step 2 (1 mark):* Expected weeks: $52 \\cdot 0.0228 \\approx 1.2$ weeks.\n\n**f. (2 marks)**\n\n*Step 1 (1 mark):* $Z = \\tfrac{17 - 20}{3} = -1$.\n\n*Step 2 (1 mark):* Sales are $1$ SD below the mean — below average.", subtopicSlugs: S },
    { content: "Blood pressure (mmHg) of healthy adults is $N(120, 64)$.\n\n**a.** Find $\\Pr(\\text{BP} > 136)$, using $\\Pr(Z < 2) = 0.9772$. (2 marks)\n\n**b.** Find $\\Pr(112 < \\text{BP} < 128)$, using $\\Pr(Z < 1) = 0.8413$. (3 marks)\n\n**c.** Find the BP exceeded by only $5\\%$ of adults, using $z = 1.645$. (2 marks)\n\n**d.** Use $\\Pr(Z < 2.575) = 0.995$ to find the central $99\\%$ interval. (3 marks)\n\n**e.** A person has BP $138$. State whether this is within the central $95\\%$ range and justify. (3 marks)", marks: 13, difficulty: "HARD", solutionContent: "**a. (2 marks)**\n\n*Step 1 (1 mark):* $\\sigma = 8$. $Z = \\tfrac{136 - 120}{8} = 2$.\n\n*Step 2 (1 mark):* $\\Pr(Z > 2) = 1 - 0.9772 = 0.0228$.\n\n**b. (3 marks)**\n\n*Step 1 (1 mark):* $Z_1 = \\tfrac{112 - 120}{8} = -1$ and $Z_2 = \\tfrac{128 - 120}{8} = 1$.\n\n*Step 2 (1 mark):* $\\Pr(-1 < Z < 1) = 2(0.8413) - 1$.\n\n*Step 3 (1 mark):* $= 0.6826$.\n\n**c. (2 marks)**\n\n*Step 1 (1 mark):* $\\Pr(Z > 1.645) = 0.05$.\n\n*Step 2 (1 mark):* BP $= 120 + 1.645 \\cdot 8 = 133.16$ mmHg.\n\n**d. (3 marks)**\n\n*Step 1 (1 mark):* Central $99\\%$: use $z = \\pm 2.575$.\n\n*Step 2 (1 mark):* Lower $= 120 - 2.575 \\cdot 8 = 99.4$ mmHg.\n\n*Step 3 (1 mark):* Upper $= 120 + 2.575 \\cdot 8 = 140.6$ mmHg.\n\n**e. (3 marks)**\n\n*Step 1 (1 mark):* Central $95\\%$ uses $z = \\pm 1.96$, so range is $120 \\pm 15.68$.\n\n*Step 2 (1 mark):* That is, $[104.32, 135.68]$ mmHg.\n\n*Step 3 (1 mark):* $138 > 135.68$, so the person is outside the central $95\\%$ range.", subtopicSlugs: S },
    { content: "The mass $M$ (grams) of a chocolate bar is normally distributed. $\\Pr(M < 48) = 0.1587$ and $\\Pr(M < 54) = 0.9772$.\n\n**a.** Using standard normal values, show that $\\mu - \\sigma = 48$ and $\\mu + 2\\sigma = 54$. (2 marks)\n\n**b.** Hence find $\\mu$ and $\\sigma$. (3 marks)\n\n**c.** Find $\\Pr(50 < M < 52)$, using $\\Pr(Z < 1) = 0.8413$. (3 marks)\n\n**d.** Find the mass exceeded by exactly $10\\%$ of bars, using $z = 1.28$. (2 marks)\n\n**e.** A bar with mass below $47$ is rejected. Find the rejection rate. (2 marks)\n\n**f.** In a sample of $1000$ bars, how many would be expected to have mass between $49$ and $51$? (2 marks)", marks: 14, difficulty: "HARD", solutionContent: "**a. (2 marks)**\n\n*Step 1 (1 mark):* $\\Pr(M < 48) = 0.1587 \\Rightarrow \\Pr(Z < -1) = 0.1587$, so $\\tfrac{48 - \\mu}{\\sigma} = -1$, giving $\\mu - \\sigma = 48$.\n\n*Step 2 (1 mark):* $\\Pr(M < 54) = 0.9772 \\Rightarrow \\Pr(Z < 2) = 0.9772$, so $\\tfrac{54 - \\mu}{\\sigma} = 2$, giving $\\mu + 2\\sigma = 54$.\n\n**b. (3 marks)**\n\n*Step 1 (1 mark):* From $\\mu - \\sigma = 48$ and $\\mu + 2\\sigma = 54$, subtract.\n\n$$3\\sigma = 6.$$\n\n*Step 2 (1 mark):* $\\sigma = 2$.\n\n*Step 3 (1 mark):* $\\mu = 48 + \\sigma = 50$.\n\n**c. (3 marks)**\n\n*Step 1 (1 mark):* Standardise.\n\n$$Z_1 = \\tfrac{50 - 50}{2} = 0, \\quad Z_2 = \\tfrac{52 - 50}{2} = 1.$$\n\n*Step 2 (1 mark):* $\\Pr(0 < Z < 1) = 0.8413 - 0.5$.\n\n*Step 3 (1 mark):* $= 0.3413$.\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* $\\Pr(Z > 1.28) = 0.10$.\n\n*Step 2 (1 mark):* Mass $= 50 + 1.28 \\cdot 2 = 52.56$ g.\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* $Z = \\tfrac{47 - 50}{2} = -1.5$.\n\n*Step 2 (1 mark):* $\\Pr(Z < -1.5) \\approx 0.0668$, so rejection rate is about $6.68\\%$.\n\n**f. (2 marks)**\n\n*Step 1 (1 mark):* $\\Pr(49 < M < 51) = \\Pr(-0.5 < Z < 0.5) \\approx 0.3829$.\n\n*Step 2 (1 mark):* Expected count: $1000 \\cdot 0.3829 \\approx 383$ bars.", subtopicSlugs: S },
  ];
  writeQset(OUT("normal-distribution"), { mcq, shortAnswer, extendedResponse });
}

