// CONFIDENCE INTERVALS
// ══════════════════════════════════════════════════════════════════════════
{
  const S = ["confidence-intervals"];
  const normalPdf = (mu: number, sigma: number) => (x: number) =>
    (1 / (sigma * Math.sqrt(2 * Math.PI))) *
    Math.exp(-0.5 * Math.pow((x - mu) / sigma, 2));
  const mcq: MCQ[] = [
    { content: "The critical $z$ value used for a $95\\%$ confidence interval is closest to:", optionA: "$1.28$", optionB: "$1.645$", optionC: "$1.96$", optionD: "$2.575$", correctOption: "C", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** For $95\\%$, the critical value is $z^* = 1.96$.\n\n**Answer: C**", subtopicSlugs: S },
    { content: "The critical $z$ value for a $99\\%$ confidence interval is approximately:", optionA: "$1.645$", optionB: "$1.96$", optionC: "$2.326$", optionD: "$2.575$", correctOption: "D", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** For $99\\%$, $z^* = 2.575$.\n\n**Answer: D**", subtopicSlugs: S },
    { content: "A $90\\%$ confidence interval for $\\mu$ based on $\\bar{x}$ uses $z^*$ equal to:", optionA: "$1.28$", optionB: "$1.645$", optionC: "$1.96$", optionD: "$2.326$", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** For $90\\%$, $z^* = 1.645$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "The margin of error for a confidence interval for a proportion is given by:", optionA: "$z^* \\hat{p}$", optionB: "$z^* \\sqrt{\\dfrac{\\hat{p}(1 - \\hat{p})}{n}}$", optionC: "$\\sqrt{\\dfrac{\\hat{p}(1 - \\hat{p})}{n}}$", optionD: "$z^* \\sqrt{\\hat{p} n}$", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Margin of error $= z^* \\sqrt{\\hat{p}(1 - \\hat{p})/n}$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "A survey of $400$ people finds $200$ prefer brand A. Then $\\hat{p}$ is:", optionA: "$0.2$", optionB: "$0.4$", optionC: "$0.5$", optionD: "$0.8$", correctOption: "C", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $\\hat{p} = \\tfrac{200}{400} = 0.5$.\n\n**Answer: C**", subtopicSlugs: S },
    { content: "All else equal, increasing the sample size $n$ in a confidence interval:", optionA: "widens the interval", optionB: "narrows the interval", optionC: "does not change the interval", optionD: "changes $\\hat{p}$", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Standard error $\\propto 1/\\sqrt{n}$, so larger $n$ shrinks the margin of error and narrows the interval.\n\n**Answer: B**", subtopicSlugs: S },
    { content: `A standard normal curve showing the central $95\\%$ region is drawn.\n\n${graphImage(normalPdf(0, 1), { xMin: -4, xMax: 4, yMin: 0, yMax: 0.45 }, "N(0,1) 95% central")}\n\nThe $z^*$ values marking the boundary of the central $95\\%$ are closest to:`, optionA: "$\\pm 1.28$", optionB: "$\\pm 1.645$", optionC: "$\\pm 1.96$", optionD: "$\\pm 2.575$", correctOption: "C", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Central $95\\%$ has $2.5\\%$ in each tail, so $z^* = 1.96$.\n\n**Answer: C**", subtopicSlugs: S },
    { content: "A sample of $100$ gives $\\bar{x} = 50$, $\\sigma = 10$. A $95\\%$ CI for $\\mu$ is:", optionA: "$50 \\pm 0.196$", optionB: "$50 \\pm 1.96$", optionC: "$50 \\pm 19.6$", optionD: "$50 \\pm 10$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Standard error $= 10/\\sqrt{100} = 1$.\n\n$$\\text{CI} = 50 \\pm 1.96(1) = 50 \\pm 1.96.$$\n\n**Answer: B**", subtopicSlugs: S },
    { content: "A sample of $500$ voters shows $300$ support a candidate. The point estimate $\\hat{p}$ is:", optionA: "$0.3$", optionB: "$0.4$", optionC: "$0.5$", optionD: "$0.6$", correctOption: "D", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $\\hat{p} = \\tfrac{300}{500} = 0.6$.\n\n**Answer: D**", subtopicSlugs: S },
    { content: "The margin of error of a $95\\%$ CI for proportion based on $n = 400$ with $\\hat{p} = 0.5$ is closest to:", optionA: "$0.025$", optionB: "$0.05$", optionC: "$0.098$", optionD: "$0.196$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Margin of error is $1.96 \\sqrt{0.5 \\cdot 0.5 / 400} = 1.96 \\cdot 0.025 = 0.049 \\approx 0.05$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "Quadrupling the sample size changes the margin of error by a factor of:", optionA: "$\\dfrac{1}{4}$", optionB: "$\\dfrac{1}{2}$", optionC: "$2$", optionD: "$4$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Margin of error $\\propto 1/\\sqrt{n}$, so $n \\to 4n$ gives factor $1/\\sqrt{4} = 1/2$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: `A table of critical $z$ values is shown.\n\n| Confidence | $z^*$ |\n|---|---|\n| $80\\%$ | $1.28$ |\n| $90\\%$ | $1.645$ |\n| $95\\%$ | $1.96$ |\n| $99\\%$ | $2.575$ |\n\nThe confidence level with the widest interval (for fixed $n$) is:`, optionA: "$80\\%$", optionB: "$90\\%$", optionC: "$95\\%$", optionD: "$99\\%$", correctOption: "D", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Higher confidence gives a larger $z^*$, so the widest interval corresponds to $99\\%$.\n\n**Answer: D**", subtopicSlugs: S },
    { content: "A $95\\%$ CI for $\\mu$ is $(8.2, 9.8)$. The point estimate $\\bar{x}$ is:", optionA: "$8.2$", optionB: "$8.8$", optionC: "$9.0$", optionD: "$9.8$", correctOption: "C", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $\\bar{x}$ is the midpoint: $\\tfrac{8.2 + 9.8}{2} = 9$.\n\n**Answer: C**", subtopicSlugs: S },
    { content: "In the CI $(8.2, 9.8)$ for $\\mu$, the margin of error is:", optionA: "$0.8$", optionB: "$1.6$", optionC: "$1.8$", optionD: "$9.0$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Half-width of the CI: $\\tfrac{9.8 - 8.2}{2} = 0.8$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "A survey finds $\\hat{p} = 0.4$ from $n = 200$. A $90\\%$ CI for $p$ has margin of error closest to:", optionA: "$0.035$", optionB: "$0.057$", optionC: "$0.068$", optionD: "$0.126$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Margin $= 1.645 \\sqrt{0.4 \\cdot 0.6 / 200} = 1.645 \\cdot 0.03464 \\approx 0.057$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "Which statement about a $95\\%$ CI is most accurate?", optionA: "There is a $95\\%$ chance the true $\\mu$ is in this specific interval", optionB: "About $95\\%$ of similarly-constructed intervals contain $\\mu$", optionC: "$95\\%$ of the population lies in the interval", optionD: "$95\\%$ of the sample lies in the interval", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** The correct interpretation: across repeated sampling, $95\\%$ of constructed CIs contain $\\mu$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "A sample of $n = 36$ gives $\\bar{x} = 20$, $\\sigma = 6$. A $99\\%$ CI for $\\mu$ is closest to:", optionA: "$(18.04, 21.96)$", optionB: "$(17.42, 22.58)$", optionC: "$(19.02, 20.98)$", optionD: "$(18.35, 21.65)$", correctOption: "B", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** SE $= 6/\\sqrt{36} = 1$. Margin $= 2.575 \\cdot 1 = 2.575$.\n\n$$\\text{CI} = 20 \\pm 2.575 = (17.425, 22.575).$$\n\n**Answer: B**", subtopicSlugs: S },
    { content: "To halve the margin of error (all else equal), the sample size must be multiplied by:", optionA: "$2$", optionB: "$4$", optionC: "$8$", optionD: "$1/2$", correctOption: "B", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** Margin $\\propto 1/\\sqrt{n}$. To halve margin, need $\\sqrt{n}$ doubled, so $n$ multiplied by $4$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "The approximate minimum sample size needed for a margin of error of at most $0.03$ for a proportion, at $95\\%$ confidence, using $\\hat{p} = 0.5$, is:", optionA: "$534$", optionB: "$751$", optionC: "$1068$", optionD: "$1537$", correctOption: "C", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** Require $1.96 \\sqrt{0.25/n} \\leq 0.03$.\n\n$$\\tfrac{1.96^2 \\cdot 0.25}{n} \\leq 0.0009 \\implies n \\geq \\tfrac{0.9604}{0.0009} \\approx 1068.$$\n\n**Answer: C**", subtopicSlugs: S },
    { content: "A $95\\%$ CI for proportion is $(0.42, 0.58)$. The sample proportion and margin are:", optionA: "$\\hat{p} = 0.50$, ME $= 0.08$", optionB: "$\\hat{p} = 0.58$, ME $= 0.08$", optionC: "$\\hat{p} = 0.50$, ME $= 0.16$", optionD: "$\\hat{p} = 0.42$, ME $= 0.16$", correctOption: "A", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $\\hat{p}$ is the midpoint: $0.50$. Margin is half-width: $0.08$.\n\n**Answer: A**", subtopicSlugs: S },
  ];
  const shortAnswer: FR[] = [
    { content: "A sample of $n = 25$ gives $\\bar{x} = 60$, $\\sigma = 10$. Compute a $95\\%$ confidence interval for $\\mu$.", marks: 2, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Standard error $= 10/\\sqrt{25} = 2$, so margin $= 1.96 \\cdot 2 = 3.92$.\n\n**Step 2 (1 mark):** CI is $60 \\pm 3.92 = (56.08, 63.92)$.", subtopicSlugs: S },
    { content: "A survey of $200$ people finds $80$ favour a proposal. Compute $\\hat{p}$ and the margin of error at $95\\%$ confidence.", marks: 2, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $\\hat{p} = 80/200 = 0.4$.\n\n**Step 2 (1 mark):** Margin $= 1.96 \\sqrt{0.4 \\cdot 0.6 / 200} \\approx 1.96 \\cdot 0.03464 \\approx 0.068$.", subtopicSlugs: S },
    { content: "State the $z^*$ used for a $90\\%$ CI, a $95\\%$ CI, and a $99\\%$ CI.", marks: 2, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $90\\%$: $z^* = 1.645$. $95\\%$: $z^* = 1.96$.\n\n**Step 2 (1 mark):** $99\\%$: $z^* = 2.575$.", subtopicSlugs: S },
    { content: "A random sample of $100$ bags of chips has mean weight $\\bar{x} = 50$ g with $\\sigma = 4$ g.\n\na. Find the $95\\%$ CI for $\\mu$. (2 marks)\n\nb. Interpret the interval in context. (1 mark)", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** SE $= 4/\\sqrt{100} = 0.4$. Margin $= 1.96 \\cdot 0.4 = 0.784$.\n\n**Step 2 (1 mark):** CI $= (49.22, 50.78)$ g.\n\n**Step 3 (1 mark):** We are $95\\%$ confident the true mean weight lies between $49.22$ g and $50.78$ g.", subtopicSlugs: S },
    { content: "A poll of $1000$ voters shows $520$ support candidate X. Find the $95\\%$ CI for the true proportion.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $\\hat{p} = 0.52$, $n = 1000$.\n\n**Step 2 (1 mark):** SE $= \\sqrt{0.52 \\cdot 0.48 / 1000} \\approx 0.0158$. Margin $= 1.96 \\cdot 0.0158 \\approx 0.031$.\n\n**Step 3 (1 mark):** CI $= (0.489, 0.551)$.", subtopicSlugs: S },
    { content: "A sample of $400$ students shows $\\hat{p} = 0.25$ prefer online study.\n\na. Compute the $90\\%$ CI. (2 marks)\n\nb. Compute the $99\\%$ CI. (1 mark)", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** SE $= \\sqrt{0.25 \\cdot 0.75 / 400} \\approx 0.0217$.\n\n**Step 2 (1 mark):** $90\\%$ margin $= 1.645 \\cdot 0.0217 \\approx 0.0357$, so CI $= (0.214, 0.286)$.\n\n**Step 3 (1 mark):** $99\\%$ margin $= 2.575 \\cdot 0.0217 \\approx 0.0559$, so CI $= (0.194, 0.306)$.", subtopicSlugs: S },
    { content: "A sample of $n = 64$ gives $\\bar{x} = 100$, $\\sigma = 16$. Construct a $99\\%$ CI for $\\mu$.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** SE $= 16/\\sqrt{64} = 2$.\n\n**Step 2 (1 mark):** Margin $= 2.575 \\cdot 2 = 5.15$.\n\n**Step 3 (1 mark):** CI $= (100 - 5.15, 100 + 5.15) = (94.85, 105.15)$.", subtopicSlugs: S },
    { content: "A researcher wants a $95\\%$ CI for a proportion with margin of error at most $0.04$. Using $\\hat{p} = 0.5$, find the minimum sample size.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Require $1.96 \\sqrt{0.25/n} \\leq 0.04$.\n\n**Step 2 (1 mark):** Solve for $n$.\n\n$$n \\geq \\tfrac{1.96^2 \\cdot 0.25}{0.04^2} = \\tfrac{0.9604}{0.0016}.$$\n\n**Step 3 (1 mark):** $n \\geq 600.25$, so at least $n = 601$.", subtopicSlugs: S },
    { content: "A sample of $36$ adults gives a mean blood pressure of $118$ mmHg with $\\sigma = 12$. Find a $95\\%$ CI for $\\mu$ and comment whether $115$ mmHg is a plausible value.", marks: 4, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** SE $= 12/\\sqrt{36} = 2$.\n\n**Step 2 (1 mark):** Margin $= 1.96 \\cdot 2 = 3.92$.\n\n**Step 3 (1 mark):** CI $= (114.08, 121.92)$.\n\n**Step 4 (1 mark):** Since $115 \\in (114.08, 121.92)$, it is a plausible value for $\\mu$.", subtopicSlugs: S },
    { content: "A $95\\%$ CI for a proportion is $(0.30, 0.40)$ from a sample of $n$.\n\na. Find $\\hat{p}$ and margin of error. (2 marks)\n\nb. Estimate $n$. (2 marks)", marks: 4, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $\\hat{p} = 0.35$, margin $= 0.05$.\n\n**Step 2 (1 mark):** Set $1.96 \\sqrt{0.35 \\cdot 0.65 / n} = 0.05$.\n\n**Step 3 (1 mark):** Square: $n = \\tfrac{1.96^2 \\cdot 0.2275}{0.0025}$.\n\n**Step 4 (1 mark):** $n \\approx 349.58$, so approximately $n = 350$.", subtopicSlugs: S },
  ];
  const extendedResponse: FR[] = [
    { content: "A sample of $100$ university students gives a mean study time of $\\bar{x} = 18$ hours per week with known population standard deviation $\\sigma = 5$ hours.\n\n**a.** State the standard error of $\\bar{x}$. (1 mark)\n\n**b.** Construct a $95\\%$ CI for $\\mu$. (2 marks)\n\n**c.** Construct a $99\\%$ CI for $\\mu$. (2 marks)\n\n**d.** Interpret the $95\\%$ CI in context. (2 marks)\n\n**e.** Find the sample size required to halve the margin of error at $95\\%$ confidence. (2 marks)\n\n**f.** Explain why the $99\\%$ CI is wider than the $95\\%$ CI. (1 mark)\n\n**g.** A rival study claims $\\mu = 20$. Is this plausible based on your $95\\%$ CI? Justify. (1 mark)", marks: 11, difficulty: "HARD", solutionContent: "**a. (1 mark)**\n\n*Step 1 (1 mark):* SE $= 5/\\sqrt{100} = 0.5$.\n\n**b. (2 marks)**\n\n*Step 1 (1 mark):* Margin $= 1.96 \\cdot 0.5 = 0.98$.\n\n*Step 2 (1 mark):* $95\\%$ CI $= (17.02, 18.98)$.\n\n**c. (2 marks)**\n\n*Step 1 (1 mark):* Margin $= 2.575 \\cdot 0.5 = 1.2875$.\n\n*Step 2 (1 mark):* $99\\%$ CI $= (16.71, 19.29)$.\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* The sample gives a range of plausible values for $\\mu$.\n\n*Step 2 (1 mark):* About $95\\%$ of such intervals, from repeated sampling, would contain the true population mean study time.\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* Halving margin requires $n \\to 4n$.\n\n*Step 2 (1 mark):* $n = 400$.\n\n**f. (1 mark)**\n\n*Step 1 (1 mark):* Higher confidence requires a larger $z^*$ ($2.575 > 1.96$), which widens the interval.\n\n**g. (1 mark)**\n\n*Step 1 (1 mark):* $20 \\notin (17.02, 18.98)$, so $\\mu = 20$ is not plausible at the $95\\%$ confidence level.", subtopicSlugs: S },
    { content: "In a poll of $n = 625$ voters, $275$ intend to vote for candidate A.\n\n**a.** Compute the sample proportion $\\hat{p}$. (1 mark)\n\n**b.** Compute the standard error of $\\hat{p}$. (2 marks)\n\n**c.** Construct a $95\\%$ CI for $p$. (2 marks)\n\n**d.** Construct a $90\\%$ CI for $p$. (2 marks)\n\n**e.** A second poll of $2500$ voters finds the same proportion. How does the new margin of error compare? (2 marks)\n\n**f.** The candidate claims $p > 0.5$. Is this supported by your $95\\%$ CI? (1 mark)", marks: 10, difficulty: "HARD", solutionContent: "**a. (1 mark)**\n\n*Step 1 (1 mark):* $\\hat{p} = 275/625 = 0.44$.\n\n**b. (2 marks)**\n\n*Step 1 (1 mark):* SE $= \\sqrt{\\hat{p}(1 - \\hat{p})/n} = \\sqrt{0.44 \\cdot 0.56 / 625}$.\n\n*Step 2 (1 mark):* $\\approx 0.01985$.\n\n**c. (2 marks)**\n\n*Step 1 (1 mark):* Margin $= 1.96 \\cdot 0.01985 \\approx 0.0389$.\n\n*Step 2 (1 mark):* $95\\%$ CI $= (0.401, 0.479)$.\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* Margin $= 1.645 \\cdot 0.01985 \\approx 0.0327$.\n\n*Step 2 (1 mark):* $90\\%$ CI $= (0.407, 0.473)$.\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* $n$ multiplied by $4$, so SE divided by $2$.\n\n*Step 2 (1 mark):* Margin of error halves.\n\n**f. (1 mark)**\n\n*Step 1 (1 mark):* The CI $(0.401, 0.479)$ lies entirely below $0.5$, so the claim $p > 0.5$ is not supported.", subtopicSlugs: S },
    { content: "A manufacturer tests $n = 49$ light bulbs and finds $\\bar{x} = 1200$ hours lifetime with $\\sigma = 140$ hours.\n\n**a.** Find the standard error of $\\bar{x}$. (1 mark)\n\n**b.** Construct a $95\\%$ CI for $\\mu$. (2 marks)\n\n**c.** Construct a $99\\%$ CI for $\\mu$. (2 marks)\n\n**d.** Compare the widths of the two CIs. (1 mark)\n\n**e.** The manufacturer claims $\\mu \\geq 1250$. Is this supported at $95\\%$ confidence? (2 marks)\n\n**f.** Find the sample size needed for a $95\\%$ CI with margin of error $10$ hours. (1 mark)", marks: 9, difficulty: "HARD", solutionContent: "**a. (1 mark)**\n\n*Step 1 (1 mark):* SE $= 140/\\sqrt{49} = 20$.\n\n**b. (2 marks)**\n\n*Step 1 (1 mark):* Margin $= 1.96 \\cdot 20 = 39.2$.\n\n*Step 2 (1 mark):* $95\\%$ CI $= (1160.8, 1239.2)$.\n\n**c. (2 marks)**\n\n*Step 1 (1 mark):* Margin $= 2.575 \\cdot 20 = 51.5$.\n\n*Step 2 (1 mark):* $99\\%$ CI $= (1148.5, 1251.5)$.\n\n**d. (1 mark)**\n\n*Step 1 (1 mark):* $99\\%$ CI is wider (half-width $51.5$ vs $39.2$).\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* $1250 \\notin (1160.8, 1239.2)$.\n\n*Step 2 (1 mark):* So the claim $\\mu \\geq 1250$ is not supported at $95\\%$ confidence.\n\n**f. (1 mark)**\n\n*Step 1 (1 mark):* $n = \\left(\\tfrac{1.96 \\cdot 140}{10}\\right)^2 \\approx 752.95$, so $n = 753$.", subtopicSlugs: S },
    { content: "A teacher wants to estimate the proportion $p$ of students who complete homework on time.\n\n**a.** In a sample of $n = 100$, $70$ complete on time. Find $\\hat{p}$ and a $95\\%$ CI for $p$. (3 marks)\n\n**b.** What sample size is needed for a $95\\%$ CI with margin of error at most $0.05$, assuming $\\hat{p} = 0.7$? (3 marks)\n\n**c.** What sample size is needed for a $95\\%$ CI with margin of error at most $0.05$, assuming the worst-case $\\hat{p} = 0.5$? (2 marks)\n\n**d.** A second survey of $n = 400$ gives $\\hat{p} = 0.72$. Find the new $95\\%$ CI and compare. (3 marks)\n\n**e.** Is $p = 0.80$ a plausible value based on the second CI? (1 mark)", marks: 12, difficulty: "HARD", solutionContent: "**a. (3 marks)**\n\n*Step 1 (1 mark):* $\\hat{p} = 0.7$.\n\n*Step 2 (1 mark):* SE $= \\sqrt{0.7 \\cdot 0.3 / 100} \\approx 0.0458$.\n\n*Step 3 (1 mark):* Margin $= 1.96 \\cdot 0.0458 \\approx 0.0898$, so CI $\\approx (0.610, 0.790)$.\n\n**b. (3 marks)**\n\n*Step 1 (1 mark):* Require $1.96 \\sqrt{0.7 \\cdot 0.3 / n} \\leq 0.05$.\n\n*Step 2 (1 mark):* $n \\geq \\tfrac{1.96^2 \\cdot 0.21}{0.0025}$.\n\n*Step 3 (1 mark):* $n \\geq 322.7$, so $n = 323$.\n\n**c. (2 marks)**\n\n*Step 1 (1 mark):* $n \\geq \\tfrac{1.96^2 \\cdot 0.25}{0.0025}$.\n\n*Step 2 (1 mark):* $n \\geq 384.16$, so $n = 385$.\n\n**d. (3 marks)**\n\n*Step 1 (1 mark):* $\\hat{p} = 0.72$, SE $= \\sqrt{0.72 \\cdot 0.28 / 400} \\approx 0.02245$.\n\n*Step 2 (1 mark):* Margin $= 1.96 \\cdot 0.02245 \\approx 0.044$, so CI $\\approx (0.676, 0.764)$.\n\n*Step 3 (1 mark):* The new CI is narrower due to larger $n$.\n\n**e. (1 mark)**\n\n*Step 1 (1 mark):* $0.80 \\notin (0.676, 0.764)$, so $p = 0.80$ is not plausible.", subtopicSlugs: S },
    { content: "A quality control department tests a new production line. A random sample of $n = 200$ items contains $10$ defectives.\n\n**a.** Compute $\\hat{p}$ for the defect rate. (1 mark)\n\n**b.** Construct a $95\\%$ CI for $p$. (3 marks)\n\n**c.** Construct a $90\\%$ CI for $p$. (2 marks)\n\n**d.** The old line had a defect rate of $3\\%$. Does your $95\\%$ CI suggest the new line is worse? (2 marks)\n\n**e.** A second sample of $800$ items has $40$ defectives. Find the new $95\\%$ CI. (3 marks)\n\n**f.** Compare the widths of the CI from part b and the CI from part e. (1 mark)\n\n**g.** Describe how margin of error depends on sample size. (1 mark)\n\n**h.** State a limitation of this inference procedure. (1 mark)", marks: 14, difficulty: "HARD", solutionContent: "**a. (1 mark)**\n\n*Step 1 (1 mark):* $\\hat{p} = 10/200 = 0.05$.\n\n**b. (3 marks)**\n\n*Step 1 (1 mark):* SE $= \\sqrt{0.05 \\cdot 0.95 / 200} \\approx 0.0154$.\n\n*Step 2 (1 mark):* Margin $= 1.96 \\cdot 0.0154 \\approx 0.0302$.\n\n*Step 3 (1 mark):* $95\\%$ CI $\\approx (0.020, 0.080)$.\n\n**c. (2 marks)**\n\n*Step 1 (1 mark):* Margin $= 1.645 \\cdot 0.0154 \\approx 0.0254$.\n\n*Step 2 (1 mark):* $90\\%$ CI $\\approx (0.025, 0.075)$.\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* $0.03$ is inside the $95\\%$ CI $(0.020, 0.080)$.\n\n*Step 2 (1 mark):* So the CI does not provide evidence that the new line is worse (the old rate is plausible).\n\n**e. (3 marks)**\n\n*Step 1 (1 mark):* $\\hat{p} = 40/800 = 0.05$.\n\n*Step 2 (1 mark):* SE $= \\sqrt{0.05 \\cdot 0.95 / 800} \\approx 0.00770$.\n\n*Step 3 (1 mark):* Margin $= 1.96 \\cdot 0.00770 \\approx 0.0151$, so CI $\\approx (0.035, 0.065)$.\n\n**f. (1 mark)**\n\n*Step 1 (1 mark):* The second CI is narrower because $n$ is $4$ times larger (margin roughly halved).\n\n**g. (1 mark)**\n\n*Step 1 (1 mark):* Margin of error decreases with $1/\\sqrt{n}$, so larger samples give tighter intervals.\n\n**h. (1 mark)**\n\n*Step 1 (1 mark):* The normal approximation requires $n\\hat{p} \\geq 10$ and $n(1 - \\hat{p}) \\geq 10$ (or similar), which may fail for very small or extreme $\\hat{p}$.", subtopicSlugs: S },
  ];
  writeQset(OUT("confidence-intervals"), { mcq, shortAnswer, extendedResponse });
}

// ══════════════════════════════════════════════════════════════════════════
// PROBABILITY RULES
// ══════════════════════════════════════════════════════════════════════════
{
  const S = ["probability-rules"];
  const mcq: MCQ[] = [
    { content: "A fair six-sided die is rolled. The probability of rolling an even number is:", optionA: "$\\dfrac{1}{6}$", optionB: "$\\dfrac{1}{3}$", optionC: "$\\dfrac{1}{2}$", optionD: "$\\dfrac{2}{3}$", correctOption: "C", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Favourable outcomes $\\{2, 4, 6\\}$ out of $6$.\n\n$$\\Pr = \\tfrac{3}{6} = \\tfrac{1}{2}.$$\n\n**Answer: C**", subtopicSlugs: S },
    { content: "If $\\Pr(A) = 0.7$, then $\\Pr(A') =$:", optionA: "$0.3$", optionB: "$0.5$", optionC: "$0.7$", optionD: "$1.0$", correctOption: "A", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Complement rule.\n\n$$\\Pr(A') = 1 - \\Pr(A) = 0.3.$$\n\n**Answer: A**", subtopicSlugs: S },
    { content: "If $\\Pr(A) = 0.4$, $\\Pr(B) = 0.3$, and $A, B$ are mutually exclusive, then $\\Pr(A \\cup B)$ equals:", optionA: "$0.1$", optionB: "$0.12$", optionC: "$0.58$", optionD: "$0.7$", correctOption: "D", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** For mutually exclusive events, $\\Pr(A \\cup B) = \\Pr(A) + \\Pr(B) = 0.4 + 0.3 = 0.7$.\n\n**Answer: D**", subtopicSlugs: S },
    { content: "If $A$ and $B$ are independent with $\\Pr(A) = 0.5$ and $\\Pr(B) = 0.4$, then $\\Pr(A \\cap B)$ equals:", optionA: "$0.1$", optionB: "$0.2$", optionC: "$0.9$", optionD: "$0.5$", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** For independent events, $\\Pr(A \\cap B) = \\Pr(A) \\Pr(B) = 0.5 \\cdot 0.4 = 0.2$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "A card is drawn from a standard $52$-card deck. The probability it is a heart is:", optionA: "$\\dfrac{1}{52}$", optionB: "$\\dfrac{1}{13}$", optionC: "$\\dfrac{1}{4}$", optionD: "$\\dfrac{1}{2}$", correctOption: "C", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** There are $13$ hearts.\n\n$$\\Pr = \\tfrac{13}{52} = \\tfrac{1}{4}.$$\n\n**Answer: C**", subtopicSlugs: S },
    { content: "Two fair coins are tossed. The probability of at least one head is:", optionA: "$\\dfrac{1}{4}$", optionB: "$\\dfrac{1}{2}$", optionC: "$\\dfrac{3}{4}$", optionD: "$1$", correctOption: "C", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $\\Pr(\\text{at least one H}) = 1 - \\Pr(\\text{no H}) = 1 - \\tfrac{1}{4} = \\tfrac{3}{4}$.\n\n**Answer: C**", subtopicSlugs: S },
    { content: "If $\\Pr(A) = 0.6$, $\\Pr(B) = 0.5$, and $\\Pr(A \\cap B) = 0.2$, then $\\Pr(A \\cup B)$ equals:", optionA: "$0.3$", optionB: "$0.7$", optionC: "$0.9$", optionD: "$1.1$", correctOption: "C", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Addition rule.\n\n$$\\Pr(A \\cup B) = \\Pr(A) + \\Pr(B) - \\Pr(A \\cap B) = 0.6 + 0.5 - 0.2 = 0.9.$$\n\n**Answer: C**", subtopicSlugs: S },
    { content: `The following table shows the distribution of $120$ students by gender and subject choice.\n\n| | Maths | Science | Total |\n|---|---|---|---|\n| Male | $30$ | $20$ | $50$ |\n| Female | $40$ | $30$ | $70$ |\n| Total | $70$ | $50$ | $120$ |\n\nThe probability a randomly selected student is female is:`, optionA: "$\\dfrac{40}{120}$", optionB: "$\\dfrac{50}{120}$", optionC: "$\\dfrac{70}{120}$", optionD: "$\\dfrac{30}{120}$", correctOption: "C", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Total females is $70$ out of $120$.\n\n$$\\Pr(F) = \\tfrac{70}{120}.$$\n\n**Answer: C**", subtopicSlugs: S },
    { content: "A bag contains $5$ red and $3$ blue balls. Two balls are drawn with replacement. The probability both are red is:", optionA: "$\\dfrac{25}{64}$", optionB: "$\\dfrac{5}{14}$", optionC: "$\\dfrac{25}{56}$", optionD: "$\\dfrac{5}{16}$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** With replacement, draws are independent.\n\n$$\\Pr(RR) = \\tfrac{5}{8} \\cdot \\tfrac{5}{8} = \\tfrac{25}{64}.$$\n\n**Answer: A**", subtopicSlugs: S },
    { content: "A bag contains $5$ red and $3$ blue balls. Two balls are drawn without replacement. The probability both are red is:", optionA: "$\\dfrac{25}{64}$", optionB: "$\\dfrac{5}{14}$", optionC: "$\\dfrac{25}{56}$", optionD: "$\\dfrac{4}{7}$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Without replacement.\n\n$$\\Pr(RR) = \\tfrac{5}{8} \\cdot \\tfrac{4}{7} = \\tfrac{20}{56} = \\tfrac{5}{14}.$$\n\n**Answer: B**", subtopicSlugs: S },
    { content: "If $\\Pr(A) = 0.4$, $\\Pr(B) = 0.5$, and $\\Pr(A \\cup B) = 0.7$, then $A$ and $B$ are:", optionA: "mutually exclusive", optionB: "independent", optionC: "equal", optionD: "complementary", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $\\Pr(A \\cap B) = 0.4 + 0.5 - 0.7 = 0.2 = 0.4 \\cdot 0.5 = \\Pr(A)\\Pr(B)$. So independent.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "A fair die is rolled twice. The probability of rolling a total of $7$ is:", optionA: "$\\dfrac{1}{6}$", optionB: "$\\dfrac{5}{36}$", optionC: "$\\dfrac{7}{36}$", optionD: "$\\dfrac{1}{12}$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Favourable pairs: $(1,6),(2,5),(3,4),(4,3),(5,2),(6,1)$ — $6$ outcomes out of $36$.\n\n$$\\Pr = \\tfrac{6}{36} = \\tfrac{1}{6}.$$\n\n**Answer: A**", subtopicSlugs: S },
    { content: `The Venn diagram summary gives $\\Pr(A \\cap B') = 0.3$, $\\Pr(A' \\cap B) = 0.2$, and $\\Pr(A \\cap B) = 0.1$. The value of $\\Pr(A \\cup B)$ is:`, optionA: "$0.3$", optionB: "$0.5$", optionC: "$0.6$", optionD: "$0.7$", correctOption: "C", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Sum of disjoint regions.\n\n$$0.3 + 0.2 + 0.1 = 0.6.$$\n\n**Answer: C**", subtopicSlugs: S },
    { content: "A box contains $4$ red, $3$ green, and $2$ yellow balls. The probability a randomly drawn ball is not green is:", optionA: "$\\dfrac{3}{9}$", optionB: "$\\dfrac{4}{9}$", optionC: "$\\dfrac{6}{9}$", optionD: "$\\dfrac{1}{9}$", correctOption: "C", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Not green $=$ red or yellow $= 6$ out of $9$.\n\n$$\\Pr = \\tfrac{6}{9} = \\tfrac{2}{3}.$$\n\n**Answer: C**", subtopicSlugs: S },
    { content: "A fair coin is tossed three times. The probability of exactly two heads is:", optionA: "$\\dfrac{1}{8}$", optionB: "$\\dfrac{3}{8}$", optionC: "$\\dfrac{1}{2}$", optionD: "$\\dfrac{5}{8}$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Favourable sequences: HHT, HTH, THH — $3$ out of $8$.\n\n$$\\Pr = \\tfrac{3}{8}.$$\n\n**Answer: B**", subtopicSlugs: S },
    { content: "A point is chosen at random on a unit square. The probability it lies within the inscribed circle of radius $1/2$ is:", optionA: "$\\dfrac{\\pi}{4}$", optionB: "$\\dfrac{\\pi}{2}$", optionC: "$\\dfrac{1}{\\pi}$", optionD: "$\\dfrac{1}{4}$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Circle area $= \\pi (1/2)^2 = \\pi/4$; square area $= 1$.\n\n$$\\Pr = \\tfrac{\\pi/4}{1} = \\tfrac{\\pi}{4}.$$\n\n**Answer: A**", subtopicSlugs: S },
    { content: "A jar has $6$ white and $4$ black marbles. Three are drawn without replacement. The probability all three are white is:", optionA: "$\\dfrac{6}{120}$", optionB: "$\\dfrac{1}{6}$", optionC: "$\\dfrac{216}{1000}$", optionD: "$\\dfrac{8}{125}$", correctOption: "B", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** Without replacement.\n\n$$\\Pr(WWW) = \\tfrac{6}{10} \\cdot \\tfrac{5}{9} \\cdot \\tfrac{4}{8} = \\tfrac{120}{720} = \\tfrac{1}{6}.$$\n\n**Answer: B**", subtopicSlugs: S },
    { content: "Two independent events $A$ and $B$ satisfy $\\Pr(A) = 0.5$ and $\\Pr(A \\cup B) = 0.7$. Then $\\Pr(B)$ equals:", optionA: "$0.2$", optionB: "$0.3$", optionC: "$0.4$", optionD: "$0.5$", correctOption: "C", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $\\Pr(A \\cup B) = \\Pr(A) + \\Pr(B) - \\Pr(A)\\Pr(B)$.\n\n$$0.7 = 0.5 + \\Pr(B)(1 - 0.5) = 0.5 + 0.5 \\Pr(B).$$\n\nSo $\\Pr(B) = 0.4$.\n\n**Answer: C**", subtopicSlugs: S },
    { content: "A and B shoot independently at a target with $\\Pr(A \\text{ hits}) = 0.8$ and $\\Pr(B \\text{ hits}) = 0.6$. The probability at least one hits is:", optionA: "$0.48$", optionB: "$0.52$", optionC: "$0.88$", optionD: "$0.92$", correctOption: "D", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** Use complement.\n\n$$\\Pr(\\text{at least one}) = 1 - \\Pr(\\text{neither}) = 1 - 0.2 \\cdot 0.4 = 1 - 0.08 = 0.92.$$\n\n**Answer: D**", subtopicSlugs: S },
    { content: "In a class, $60\\%$ play soccer and $50\\%$ play tennis. If $30\\%$ play both, then the probability a student plays neither is:", optionA: "$0.1$", optionB: "$0.2$", optionC: "$0.3$", optionD: "$0.4$", correctOption: "B", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $\\Pr(S \\cup T) = 0.6 + 0.5 - 0.3 = 0.8$. $\\Pr(\\text{neither}) = 1 - 0.8 = 0.2$.\n\n**Answer: B**", subtopicSlugs: S },
  ];
  const shortAnswer: FR[] = [
    { content: "A bag has $4$ red, $3$ blue, and $3$ green balls. A ball is drawn at random.\n\na. Find $\\Pr(\\text{red})$. (1 mark)\n\nb. Find $\\Pr(\\text{not blue})$. (1 mark)", marks: 2, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $\\Pr(R) = \\tfrac{4}{10} = \\tfrac{2}{5}$.\n\n**Step 2 (1 mark):** $\\Pr(B') = 1 - \\tfrac{3}{10} = \\tfrac{7}{10}$.", subtopicSlugs: S },
    { content: "Given $\\Pr(A) = 0.7$ and $\\Pr(B) = 0.5$ with $\\Pr(A \\cap B) = 0.3$, find $\\Pr(A \\cup B)$.", marks: 2, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Addition rule.\n\n$$\\Pr(A \\cup B) = 0.7 + 0.5 - 0.3.$$\n\n**Step 2 (1 mark):** $= 0.9$.", subtopicSlugs: S },
    { content: "Two fair dice are rolled. Find the probability the sum equals $8$.", marks: 2, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Favourable pairs: $(2,6),(3,5),(4,4),(5,3),(6,2)$ — $5$ outcomes.\n\n**Step 2 (1 mark):** $\\Pr = \\tfrac{5}{36}$.", subtopicSlugs: S },
    { content: "$A$ and $B$ are independent events with $\\Pr(A) = 0.4$ and $\\Pr(B) = 0.6$.\n\na. Find $\\Pr(A \\cap B)$. (1 mark)\n\nb. Find $\\Pr(A \\cup B)$. (2 marks)", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $\\Pr(A \\cap B) = 0.4 \\cdot 0.6 = 0.24$.\n\n**Step 2 (1 mark):** $\\Pr(A \\cup B) = \\Pr(A) + \\Pr(B) - \\Pr(A \\cap B)$.\n\n**Step 3 (1 mark):** $= 0.4 + 0.6 - 0.24 = 0.76$.", subtopicSlugs: S },
    { content: `A survey of $200$ people gives the following table:\n\n| | Owns car | No car | Total |\n|---|---|---|---|\n| Employed | $70$ | $30$ | $100$ |\n| Unemployed | $40$ | $60$ | $100$ |\n| Total | $110$ | $90$ | $200$ |\n\na. Find $\\Pr(\\text{owns car})$. (1 mark)\n\nb. Find $\\Pr(\\text{employed and owns car})$. (1 mark)\n\nc. Find $\\Pr(\\text{employed or owns car})$. (1 mark)`, marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $\\Pr(\\text{car}) = \\tfrac{110}{200} = 0.55$.\n\n**Step 2 (1 mark):** $\\Pr(\\text{Emp} \\cap \\text{Car}) = \\tfrac{70}{200} = 0.35$.\n\n**Step 3 (1 mark):** $\\Pr(\\text{Emp} \\cup \\text{Car}) = \\tfrac{100 + 110 - 70}{200} = \\tfrac{140}{200} = 0.70$.", subtopicSlugs: S },
    { content: "A box has $5$ red and $3$ blue balls. Two balls are drawn without replacement.\n\na. Find $\\Pr(\\text{both red})$. (1 mark)\n\nb. Find $\\Pr(\\text{one of each colour})$. (2 marks)", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $\\Pr(RR) = \\tfrac{5}{8} \\cdot \\tfrac{4}{7} = \\tfrac{20}{56} = \\tfrac{5}{14}$.\n\n**Step 2 (1 mark):** $\\Pr(RB) = \\tfrac{5}{8} \\cdot \\tfrac{3}{7} = \\tfrac{15}{56}$ and $\\Pr(BR) = \\tfrac{3}{8} \\cdot \\tfrac{5}{7} = \\tfrac{15}{56}$.\n\n**Step 3 (1 mark):** $\\Pr(\\text{one of each}) = \\tfrac{15}{56} + \\tfrac{15}{56} = \\tfrac{30}{56} = \\tfrac{15}{28}$.", subtopicSlugs: S },
    { content: "A point is chosen uniformly at random in a square of side $4$. A smaller square of side $2$ is inside it.\n\na. Find the probability the point lies in the smaller square. (2 marks)\n\nb. Find the probability the point lies outside the smaller square. (1 mark)", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Small square area $= 4$, large square area $= 16$.\n\n**Step 2 (1 mark):** $\\Pr(\\text{inside small}) = \\tfrac{4}{16} = \\tfrac{1}{4}$.\n\n**Step 3 (1 mark):** $\\Pr(\\text{outside small}) = 1 - \\tfrac{1}{4} = \\tfrac{3}{4}$.", subtopicSlugs: S },
    { content: "A fair coin is tossed $4$ times.\n\na. Find the probability of exactly $2$ heads. (2 marks)\n\nb. Find the probability of at least $1$ head. (1 mark)", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Favourable sequences count $= \\binom{4}{2} = 6$, total $= 16$.\n\n**Step 2 (1 mark):** $\\Pr = \\tfrac{6}{16} = \\tfrac{3}{8}$.\n\n**Step 3 (1 mark):** $\\Pr(\\text{at least 1 H}) = 1 - \\tfrac{1}{16} = \\tfrac{15}{16}$.", subtopicSlugs: S },
    { content: "$A$ and $B$ are events with $\\Pr(A) = 0.6$, $\\Pr(B) = 0.5$, and $\\Pr(A \\cap B) = 0.2$.\n\na. Find $\\Pr(A \\cup B)$. (1 mark)\n\nb. Determine whether $A$ and $B$ are independent. (2 marks)\n\nc. Find $\\Pr(A' \\cap B')$. (1 mark)", marks: 4, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $\\Pr(A \\cup B) = 0.6 + 0.5 - 0.2 = 0.9$.\n\n**Step 2 (1 mark):** $\\Pr(A) \\Pr(B) = 0.6 \\cdot 0.5 = 0.3$.\n\n**Step 3 (1 mark):** Since $\\Pr(A \\cap B) = 0.2 \\neq 0.3 = \\Pr(A)\\Pr(B)$, they are not independent.\n\n**Step 4 (1 mark):** $\\Pr(A' \\cap B') = 1 - \\Pr(A \\cup B) = 0.1$.", subtopicSlugs: S },
    { content: "Three independent events $A$, $B$, $C$ have $\\Pr(A) = 0.3$, $\\Pr(B) = 0.5$, $\\Pr(C) = 0.4$.\n\na. Find $\\Pr(\\text{all three occur})$. (1 mark)\n\nb. Find $\\Pr(\\text{none occur})$. (2 marks)", marks: 3, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $\\Pr(A \\cap B \\cap C) = 0.3 \\cdot 0.5 \\cdot 0.4 = 0.06$.\n\n**Step 2 (1 mark):** $\\Pr(\\text{none}) = \\Pr(A') \\Pr(B') \\Pr(C')$.\n\n**Step 3 (1 mark):** $= 0.7 \\cdot 0.5 \\cdot 0.6 = 0.21$.", subtopicSlugs: S },
  ];
  const extendedResponse: FR[] = [
    { content: "A box contains $6$ red marbles and $4$ blue marbles.\n\n**a.** A marble is drawn at random. Find $\\Pr(\\text{red})$. (1 mark)\n\n**b.** Two marbles are drawn with replacement. Find $\\Pr(\\text{both red})$. (2 marks)\n\n**c.** Two marbles are drawn without replacement. Find $\\Pr(\\text{both red})$. (2 marks)\n\n**d.** Two marbles are drawn without replacement. Find $\\Pr(\\text{one of each colour})$. (3 marks)\n\n**e.** Three marbles are drawn without replacement. Find $\\Pr(\\text{all three red})$. (2 marks)\n\n**f.** Explain why the probability of both red differs between with- and without-replacement. (1 mark)", marks: 11, difficulty: "HARD", solutionContent: "**a. (1 mark)**\n\n*Step 1 (1 mark):* $\\Pr(R) = \\tfrac{6}{10} = \\tfrac{3}{5}$.\n\n**b. (2 marks)**\n\n*Step 1 (1 mark):* Draws are independent.\n\n*Step 2 (1 mark):* $\\Pr(RR) = \\tfrac{3}{5} \\cdot \\tfrac{3}{5} = \\tfrac{9}{25}$.\n\n**c. (2 marks)**\n\n*Step 1 (1 mark):* Without replacement.\n\n*Step 2 (1 mark):* $\\Pr(RR) = \\tfrac{6}{10} \\cdot \\tfrac{5}{9} = \\tfrac{30}{90} = \\tfrac{1}{3}$.\n\n**d. (3 marks)**\n\n*Step 1 (1 mark):* $\\Pr(RB) = \\tfrac{6}{10} \\cdot \\tfrac{4}{9} = \\tfrac{24}{90}$.\n\n*Step 2 (1 mark):* $\\Pr(BR) = \\tfrac{4}{10} \\cdot \\tfrac{6}{9} = \\tfrac{24}{90}$.\n\n*Step 3 (1 mark):* Sum $= \\tfrac{48}{90} = \\tfrac{8}{15}$.\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* $\\Pr(RRR) = \\tfrac{6}{10} \\cdot \\tfrac{5}{9} \\cdot \\tfrac{4}{8}$.\n\n*Step 2 (1 mark):* $= \\tfrac{120}{720} = \\tfrac{1}{6}$.\n\n**f. (1 mark)**\n\n*Step 1 (1 mark):* Without replacement the pool shrinks, so the probability of a second red decreases, making the joint probability smaller than with replacement.", subtopicSlugs: S },
    { content: "Two events $A$ and $B$ satisfy $\\Pr(A) = 0.6$, $\\Pr(B) = 0.4$, and $\\Pr(A \\cup B) = 0.8$.\n\n**a.** Find $\\Pr(A \\cap B)$. (2 marks)\n\n**b.** Are $A$ and $B$ independent? Justify. (2 marks)\n\n**c.** Find $\\Pr(A \\cap B')$. (2 marks)\n\n**d.** Find $\\Pr(A' \\cap B')$. (2 marks)\n\n**e.** If a third event $C$ is independent of both $A$ and $B$ with $\\Pr(C) = 0.5$, find $\\Pr(A \\cap C)$. (2 marks)", marks: 10, difficulty: "HARD", solutionContent: "**a. (2 marks)**\n\n*Step 1 (1 mark):* $\\Pr(A \\cap B) = \\Pr(A) + \\Pr(B) - \\Pr(A \\cup B)$.\n\n*Step 2 (1 mark):* $= 0.6 + 0.4 - 0.8 = 0.2$.\n\n**b. (2 marks)**\n\n*Step 1 (1 mark):* $\\Pr(A)\\Pr(B) = 0.24$.\n\n*Step 2 (1 mark):* $\\Pr(A \\cap B) = 0.2 \\neq 0.24$, so not independent.\n\n**c. (2 marks)**\n\n*Step 1 (1 mark):* $\\Pr(A \\cap B') = \\Pr(A) - \\Pr(A \\cap B)$.\n\n*Step 2 (1 mark):* $= 0.6 - 0.2 = 0.4$.\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* $\\Pr(A' \\cap B') = 1 - \\Pr(A \\cup B)$.\n\n*Step 2 (1 mark):* $= 0.2$.\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* Independence.\n\n*Step 2 (1 mark):* $\\Pr(A \\cap C) = 0.6 \\cdot 0.5 = 0.3$.", subtopicSlugs: S },
    { content: "A class of $30$ students has $18$ girls and $12$ boys. In the class, $20$ study French and $15$ study Spanish, with $8$ studying both.\n\n**a.** Draw a Venn diagram for French and Spanish. Find the number who study only French. (2 marks)\n\n**b.** Find the number who study neither. (2 marks)\n\n**c.** A student is selected at random. Find $\\Pr(\\text{studies French or Spanish})$. (2 marks)\n\n**d.** Find $\\Pr(\\text{studies only Spanish})$. (2 marks)\n\n**e.** If $60\\%$ of girls study French, how many girls study French? (2 marks)\n\n**f.** Explain what $\\Pr(F')$ represents in context. (1 mark)", marks: 11, difficulty: "HARD", solutionContent: "**a. (2 marks)**\n\n*Step 1 (1 mark):* Only French $= 20 - 8$.\n\n*Step 2 (1 mark):* $= 12$ students.\n\n**b. (2 marks)**\n\n*Step 1 (1 mark):* Union $= 20 + 15 - 8 = 27$.\n\n*Step 2 (1 mark):* Neither $= 30 - 27 = 3$ students.\n\n**c. (2 marks)**\n\n*Step 1 (1 mark):* Union $= 27$.\n\n*Step 2 (1 mark):* $\\Pr(F \\cup S) = \\tfrac{27}{30} = 0.9$.\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* Only Spanish $= 15 - 8 = 7$.\n\n*Step 2 (1 mark):* $\\Pr(\\text{only S}) = \\tfrac{7}{30}$.\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* $0.6 \\cdot 18$.\n\n*Step 2 (1 mark):* $= 10.8$, rounded to $11$ girls.\n\n**f. (1 mark)**\n\n*Step 1 (1 mark):* $\\Pr(F')$ is the probability a randomly chosen student does not study French.", subtopicSlugs: S },
    { content: "A biased coin has $\\Pr(H) = 0.6$. It is tossed three times independently.\n\n**a.** Find $\\Pr(HHH)$. (1 mark)\n\n**b.** Find $\\Pr(\\text{no heads})$. (2 marks)\n\n**c.** Find $\\Pr(\\text{exactly one head})$. (3 marks)\n\n**d.** Find $\\Pr(\\text{exactly two heads})$. (2 marks)\n\n**e.** Find $\\Pr(\\text{at least one head})$. (1 mark)\n\n**f.** Verify that the probabilities in parts (b), (c), (d), and $\\Pr(HHH)$ sum to $1$. (1 mark)\n\n**g.** State the expected number of heads in $3$ tosses. (2 marks)", marks: 12, difficulty: "HARD", solutionContent: "**a. (1 mark)**\n\n*Step 1 (1 mark):* $0.6^3 = 0.216$.\n\n**b. (2 marks)**\n\n*Step 1 (1 mark):* $\\Pr(T) = 0.4$.\n\n*Step 2 (1 mark):* $0.4^3 = 0.064$.\n\n**c. (3 marks)**\n\n*Step 1 (1 mark):* Choose position of $H$: $\\binom{3}{1} = 3$ arrangements.\n\n*Step 2 (1 mark):* Each has probability $0.6 \\cdot 0.4^2 = 0.096$.\n\n*Step 3 (1 mark):* Total $= 3 \\cdot 0.096 = 0.288$.\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* $\\binom{3}{2} = 3$ arrangements, each with probability $0.6^2 \\cdot 0.4 = 0.144$.\n\n*Step 2 (1 mark):* Total $= 3 \\cdot 0.144 = 0.432$.\n\n**e. (1 mark)**\n\n*Step 1 (1 mark):* $1 - 0.064 = 0.936$.\n\n**f. (1 mark)**\n\n*Step 1 (1 mark):* $0.064 + 0.288 + 0.432 + 0.216 = 1$ ✓.\n\n**g. (2 marks)**\n\n*Step 1 (1 mark):* $E(H) = np = 3 \\cdot 0.6$.\n\n*Step 2 (1 mark):* $= 1.8$ heads.", subtopicSlugs: S },
    { content: "A game consists of drawing marbles from a bag containing $3$ red, $4$ green, and $5$ blue marbles.\n\n**a.** One marble is drawn. Find $\\Pr(R)$, $\\Pr(G)$, $\\Pr(B)$. (2 marks)\n\n**b.** Two marbles are drawn without replacement. Find $\\Pr(\\text{both red})$. (2 marks)\n\n**c.** Two marbles are drawn without replacement. Find $\\Pr(\\text{same colour})$. (4 marks)\n\n**d.** Two marbles are drawn without replacement. Find $\\Pr(\\text{different colours})$. (2 marks)\n\n**e.** A marble is replaced after each draw. Three draws are made. Find $\\Pr(\\text{three different colours})$. (3 marks)\n\n**f.** Find $\\Pr(\\text{at least one red in three draws with replacement})$. (2 marks)", marks: 15, difficulty: "HARD", solutionContent: "**a. (2 marks)**\n\n*Step 1 (1 mark):* $\\Pr(R) = \\tfrac{3}{12} = \\tfrac{1}{4}$, $\\Pr(G) = \\tfrac{4}{12} = \\tfrac{1}{3}$.\n\n*Step 2 (1 mark):* $\\Pr(B) = \\tfrac{5}{12}$.\n\n**b. (2 marks)**\n\n*Step 1 (1 mark):* Without replacement.\n\n*Step 2 (1 mark):* $\\Pr(RR) = \\tfrac{3}{12} \\cdot \\tfrac{2}{11} = \\tfrac{6}{132} = \\tfrac{1}{22}$.\n\n**c. (4 marks)**\n\n*Step 1 (1 mark):* $\\Pr(RR) = \\tfrac{6}{132}$.\n\n*Step 2 (1 mark):* $\\Pr(GG) = \\tfrac{4}{12} \\cdot \\tfrac{3}{11} = \\tfrac{12}{132}$.\n\n*Step 3 (1 mark):* $\\Pr(BB) = \\tfrac{5}{12} \\cdot \\tfrac{4}{11} = \\tfrac{20}{132}$.\n\n*Step 4 (1 mark):* Sum $= \\tfrac{38}{132} = \\tfrac{19}{66}$.\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* Complement of same colour.\n\n*Step 2 (1 mark):* $1 - \\tfrac{19}{66} = \\tfrac{47}{66}$.\n\n**e. (3 marks)**\n\n*Step 1 (1 mark):* Draws independent with replacement.\n\n*Step 2 (1 mark):* Number of orderings of RGB $= 3! = 6$.\n\n*Step 3 (1 mark):* $\\Pr = 6 \\cdot \\tfrac{1}{4} \\cdot \\tfrac{1}{3} \\cdot \\tfrac{5}{12} = \\tfrac{30}{144} = \\tfrac{5}{24}$.\n\n**f. (2 marks)**\n\n*Step 1 (1 mark):* Complement.\n\n*Step 2 (1 mark):* $1 - \\left(\\tfrac{9}{12}\\right)^3 = 1 - \\tfrac{729}{1728} = 1 - 0.4219 = 0.5781$.", subtopicSlugs: S },
  ];
  writeQset(OUT("probability-rules"), { mcq, shortAnswer, extendedResponse });
}

