// CONDITIONAL PROBABILITY
// ══════════════════════════════════════════════════════════════════════════
{
  const S = ["conditional-probability"];
  const mcq: MCQ[] = [
    { content: "The conditional probability $\\Pr(A \\mid B)$ is defined as:", optionA: "$\\Pr(A) \\cdot \\Pr(B)$", optionB: "$\\dfrac{\\Pr(A \\cap B)}{\\Pr(B)}$", optionC: "$\\dfrac{\\Pr(B)}{\\Pr(A \\cap B)}$", optionD: "$\\Pr(A) + \\Pr(B)$", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Definition of conditional probability.\n\n$$\\Pr(A \\mid B) = \\tfrac{\\Pr(A \\cap B)}{\\Pr(B)}.$$\n\n**Answer: B**", subtopicSlugs: S },
    { content: "If $\\Pr(A \\cap B) = 0.2$ and $\\Pr(B) = 0.5$, then $\\Pr(A \\mid B)$ equals:", optionA: "$0.1$", optionB: "$0.25$", optionC: "$0.4$", optionD: "$0.7$", correctOption: "C", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Apply the formula.\n\n$$\\Pr(A \\mid B) = \\tfrac{0.2}{0.5} = 0.4.$$\n\n**Answer: C**", subtopicSlugs: S },
    { content: "If $A$ and $B$ are independent, then $\\Pr(A \\mid B)$ equals:", optionA: "$0$", optionB: "$\\Pr(A)$", optionC: "$\\Pr(B)$", optionD: "$1$", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Independence means $B$ gives no information about $A$.\n\n$$\\Pr(A \\mid B) = \\Pr(A).$$\n\n**Answer: B**", subtopicSlugs: S },
    { content: "For $\\Pr(A) = 0.5$ and $\\Pr(B \\mid A) = 0.4$, then $\\Pr(A \\cap B)$ equals:", optionA: "$0.1$", optionB: "$0.2$", optionC: "$0.4$", optionD: "$0.9$", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Multiplication rule.\n\n$$\\Pr(A \\cap B) = \\Pr(A) \\cdot \\Pr(B \\mid A) = 0.5 \\cdot 0.4 = 0.2.$$\n\n**Answer: B**", subtopicSlugs: S },
    { content: "In a survey, $60\\%$ of people own a pet and of pet owners, $50\\%$ have a dog. The probability a randomly selected person owns a dog is:", optionA: "$0.10$", optionB: "$0.30$", optionC: "$0.50$", optionD: "$0.60$", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $\\Pr(\\text{dog}) = \\Pr(\\text{pet}) \\cdot \\Pr(\\text{dog} \\mid \\text{pet}) = 0.6 \\cdot 0.5 = 0.3$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "A card is drawn from a standard deck. Given that the card is red, the probability it is a heart is:", optionA: "$\\dfrac{1}{4}$", optionB: "$\\dfrac{1}{2}$", optionC: "$\\dfrac{1}{13}$", optionD: "$\\dfrac{13}{26}$", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Among $26$ red cards, $13$ are hearts.\n\n$$\\Pr(\\text{heart} \\mid \\text{red}) = \\tfrac{13}{26} = \\tfrac{1}{2}.$$\n\n**Answer: B**", subtopicSlugs: S },
    { content: `The table gives a two-way classification for $200$ students.\n\n| | Pass | Fail | Total |\n|---|---|---|---|\n| Male | $60$ | $20$ | $80$ |\n| Female | $90$ | $30$ | $120$ |\n| Total | $150$ | $50$ | $200$ |\n\nGiven a student passed, the probability the student is female is:`, optionA: "$\\dfrac{90}{200}$", optionB: "$\\dfrac{90}{120}$", optionC: "$\\dfrac{90}{150}$", optionD: "$\\dfrac{120}{200}$", correctOption: "C", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Condition on passed.\n\n$$\\Pr(F \\mid P) = \\tfrac{90}{150} = 0.6.$$\n\n**Answer: C**", subtopicSlugs: S },
    { content: `From the same table, the probability a student passes given that the student is female is:`, optionA: "$\\dfrac{90}{200}$", optionB: "$\\dfrac{90}{120}$", optionC: "$\\dfrac{90}{150}$", optionD: "$\\dfrac{120}{200}$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Condition on female.\n\n$$\\Pr(P \\mid F) = \\tfrac{90}{120} = 0.75.$$\n\n**Answer: B**", subtopicSlugs: S },
    { content: "A bag has $5$ red and $3$ blue balls. Two are drawn without replacement. Given the first is red, the probability the second is red is:", optionA: "$\\dfrac{3}{7}$", optionB: "$\\dfrac{4}{7}$", optionC: "$\\dfrac{4}{8}$", optionD: "$\\dfrac{5}{8}$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** After one red removed, $4$ red out of $7$ remain.\n\n$$\\Pr = \\tfrac{4}{7}.$$\n\n**Answer: B**", subtopicSlugs: S },
    { content: "If $\\Pr(A) = 0.6$, $\\Pr(B) = 0.4$, and $\\Pr(A \\mid B) = 0.5$, then $\\Pr(A \\cap B)$ equals:", optionA: "$0.2$", optionB: "$0.24$", optionC: "$0.3$", optionD: "$0.5$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $\\Pr(A \\cap B) = \\Pr(A \\mid B) \\cdot \\Pr(B) = 0.5 \\cdot 0.4 = 0.2$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "If $\\Pr(A) = 0.3$, $\\Pr(B) = 0.4$, $\\Pr(A \\cap B) = 0.12$, then $A$ and $B$ are:", optionA: "mutually exclusive", optionB: "independent", optionC: "not independent", optionD: "complementary", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $\\Pr(A)\\Pr(B) = 0.12 = \\Pr(A \\cap B)$, so independent.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "A fair die is rolled. Given the roll is even, the probability it is greater than $3$ is:", optionA: "$\\dfrac{1}{6}$", optionB: "$\\dfrac{1}{3}$", optionC: "$\\dfrac{2}{3}$", optionD: "$\\dfrac{1}{2}$", correctOption: "C", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Even outcomes $\\{2, 4, 6\\}$; of these, $\\{4, 6\\}$ are $> 3$.\n\n$$\\Pr = \\tfrac{2}{3}.$$\n\n**Answer: C**", subtopicSlugs: S },
    { content: "In a two-stage experiment, $\\Pr(A) = 0.4$ and $\\Pr(B \\mid A) = 0.5$, $\\Pr(B \\mid A') = 0.3$. Then $\\Pr(B)$ equals:", optionA: "$0.30$", optionB: "$0.38$", optionC: "$0.50$", optionD: "$0.80$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Law of total probability.\n\n$$\\Pr(B) = \\Pr(A) \\Pr(B \\mid A) + \\Pr(A') \\Pr(B \\mid A') = 0.4 \\cdot 0.5 + 0.6 \\cdot 0.3 = 0.38.$$\n\n**Answer: B**", subtopicSlugs: S },
    { content: "A test for a disease has $95\\%$ sensitivity. If a person has the disease, the probability of testing positive is:", optionA: "$0.05$", optionB: "$0.50$", optionC: "$0.95$", optionD: "$1.00$", correctOption: "C", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Sensitivity = $\\Pr(\\text{positive} \\mid \\text{disease}) = 0.95$.\n\n**Answer: C**", subtopicSlugs: S },
    { content: `For the classification table below, $\\Pr(\\text{Red} \\mid \\text{Small})$ equals:\n\n| | Small | Large | Total |\n|---|---|---|---|\n| Red | $30$ | $40$ | $70$ |\n| Blue | $20$ | $10$ | $30$ |\n| Total | $50$ | $50$ | $100$ |\n`, optionA: "$\\dfrac{30}{50}$", optionB: "$\\dfrac{30}{70}$", optionC: "$\\dfrac{30}{100}$", optionD: "$\\dfrac{50}{100}$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Condition on Small: $\\tfrac{30}{50} = 0.6$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "From the table above, $\\Pr(\\text{Small} \\mid \\text{Red})$ equals:", optionA: "$\\dfrac{30}{50}$", optionB: "$\\dfrac{30}{70}$", optionC: "$\\dfrac{30}{100}$", optionD: "$\\dfrac{50}{100}$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Condition on Red: $\\tfrac{30}{70}$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "A rare disease affects $1\\%$ of a population. A test has sensitivity $99\\%$ and specificity $95\\%$. Given a positive test, the probability the person has the disease is approximately (Bayes):", optionA: "$0.01$", optionB: "$0.17$", optionC: "$0.50$", optionD: "$0.99$", correctOption: "B", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** Apply Bayes.\n\n$$\\Pr(D \\mid +) = \\tfrac{0.01 \\cdot 0.99}{0.01 \\cdot 0.99 + 0.99 \\cdot 0.05} = \\tfrac{0.0099}{0.0099 + 0.0495} = \\tfrac{0.0099}{0.0594} \\approx 0.167.$$\n\n**Answer: B**", subtopicSlugs: S },
    { content: "Two dice are rolled. Given the sum is $6$, the probability the first die shows $2$ is:", optionA: "$\\dfrac{1}{6}$", optionB: "$\\dfrac{1}{5}$", optionC: "$\\dfrac{1}{4}$", optionD: "$\\dfrac{1}{3}$", correctOption: "B", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** Sum $=6$ has $5$ outcomes: $(1,5),(2,4),(3,3),(4,2),(5,1)$. Of these, $1$ has first die $= 2$.\n\n$$\\Pr = \\tfrac{1}{5}.$$\n\n**Answer: B**", subtopicSlugs: S },
    { content: "In a box, $\\Pr(A) = 0.6$, $\\Pr(B) = 0.5$, and $\\Pr(A \\cup B) = 0.8$. Then $\\Pr(A \\mid B)$ equals:", optionA: "$0.3$", optionB: "$0.4$", optionC: "$0.5$", optionD: "$0.6$", correctOption: "D", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $\\Pr(A \\cap B) = 0.6 + 0.5 - 0.8 = 0.3$.\n\n**Step 2:** $\\Pr(A \\mid B) = \\tfrac{0.3}{0.5} = 0.6$.\n\n**Answer: D**", subtopicSlugs: S },
    { content: "Of cars at a dealer, $40\\%$ are red, $60\\%$ other. Of red cars, $25\\%$ are sports. Of non-red cars, $10\\%$ are sports. The probability a random car is red given it is a sports car is closest to:", optionA: "$0.25$", optionB: "$0.40$", optionC: "$0.63$", optionD: "$0.80$", correctOption: "C", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** Bayes:\n\n$$\\Pr(R \\mid S) = \\tfrac{0.4 \\cdot 0.25}{0.4 \\cdot 0.25 + 0.6 \\cdot 0.1} = \\tfrac{0.1}{0.16} = 0.625.$$\n\n**Answer: C**", subtopicSlugs: S },
  ];
  const shortAnswer: FR[] = [
    { content: "Given $\\Pr(A) = 0.5$, $\\Pr(B) = 0.4$, $\\Pr(A \\cap B) = 0.2$, find $\\Pr(A \\mid B)$.", marks: 2, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Formula.\n\n$$\\Pr(A \\mid B) = \\tfrac{\\Pr(A \\cap B)}{\\Pr(B)}.$$\n\n**Step 2 (1 mark):** $= \\tfrac{0.2}{0.4} = 0.5$.", subtopicSlugs: S },
    { content: `A two-way table of $100$ students:\n\n| | Glasses | No glasses |\n|---|---|---|\n| Male | $15$ | $35$ |\n| Female | $20$ | $30$ |\n\na. Find $\\Pr(\\text{glasses})$. (1 mark)\n\nb. Find $\\Pr(\\text{glasses} \\mid \\text{female})$. (1 mark)`, marks: 2, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $\\Pr(\\text{glasses}) = \\tfrac{35}{100} = 0.35$.\n\n**Step 2 (1 mark):** $\\Pr(\\text{glasses} \\mid F) = \\tfrac{20}{50} = 0.4$.", subtopicSlugs: S },
    { content: "A card is drawn from a standard deck. Given it is a face card, find the probability it is a king.", marks: 2, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** There are $12$ face cards (J, Q, K of each suit).\n\n**Step 2 (1 mark):** Of these, $4$ are kings.\n\n$$\\Pr = \\tfrac{4}{12} = \\tfrac{1}{3}.$$", subtopicSlugs: S },
    { content: "A box has $6$ red and $4$ blue balls. Two are drawn without replacement.\n\na. Find $\\Pr(\\text{second is red} \\mid \\text{first is red})$. (1 mark)\n\nb. Find $\\Pr(\\text{first is red and second is blue})$. (2 marks)", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** After first red removed, $5$ red remain in $9$ balls. $\\Pr = \\tfrac{5}{9}$.\n\n**Step 2 (1 mark):** $\\Pr(RB) = \\Pr(R) \\cdot \\Pr(B \\mid R)$.\n\n**Step 3 (1 mark):** $= \\tfrac{6}{10} \\cdot \\tfrac{4}{9} = \\tfrac{24}{90} = \\tfrac{4}{15}$.", subtopicSlugs: S },
    { content: "In a school, $40\\%$ of students study Physics. Of those, $70\\%$ also study Maths. Of those not studying Physics, $50\\%$ study Maths.\n\na. Find $\\Pr(\\text{Maths})$. (2 marks)\n\nb. Given a student studies Maths, find $\\Pr(\\text{Physics})$. (2 marks)", marks: 4, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Total probability.\n\n$$\\Pr(M) = 0.4 \\cdot 0.7 + 0.6 \\cdot 0.5.$$\n\n**Step 2 (1 mark):** $= 0.28 + 0.30 = 0.58$.\n\n**Step 3 (1 mark):** $\\Pr(P \\mid M) = \\tfrac{\\Pr(P \\cap M)}{\\Pr(M)} = \\tfrac{0.28}{0.58}$.\n\n**Step 4 (1 mark):** $\\approx 0.483$.", subtopicSlugs: S },
    { content: "$\\Pr(A) = 0.5$, $\\Pr(B) = 0.4$. Determine whether $A$ and $B$ are independent if $\\Pr(A \\cap B) = 0.25$.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Compute $\\Pr(A)\\Pr(B) = 0.20$.\n\n**Step 2 (1 mark):** Compare with $\\Pr(A \\cap B) = 0.25$.\n\n**Step 3 (1 mark):** Since $0.25 \\neq 0.20$, $A$ and $B$ are not independent.", subtopicSlugs: S },
    { content: "A test for a disease has sensitivity $0.90$ and specificity $0.80$. The disease prevalence is $0.05$.\n\na. Find $\\Pr(\\text{positive test})$. (2 marks)\n\nb. Find $\\Pr(\\text{disease} \\mid \\text{positive})$. (2 marks)", marks: 4, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $\\Pr(+) = 0.05 \\cdot 0.90 + 0.95 \\cdot 0.20$.\n\n**Step 2 (1 mark):** $= 0.045 + 0.19 = 0.235$.\n\n**Step 3 (1 mark):** Bayes:\n\n$$\\Pr(D \\mid +) = \\tfrac{0.045}{0.235}.$$\n\n**Step 4 (1 mark):** $\\approx 0.191$.", subtopicSlugs: S },
    { content: "Two fair dice are rolled. Let $A$ be the event the first die is $4$ and $B$ be the event the sum is $7$. Find $\\Pr(A \\mid B)$.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $\\Pr(B) = \\tfrac{6}{36} = \\tfrac{1}{6}$.\n\n**Step 2 (1 mark):** $A \\cap B$: first die $= 4$ and sum $= 7$, so second $= 3$ — one outcome. $\\Pr(A \\cap B) = \\tfrac{1}{36}$.\n\n**Step 3 (1 mark):** $\\Pr(A \\mid B) = \\tfrac{1/36}{6/36} = \\tfrac{1}{6}$.", subtopicSlugs: S },
    { content: "In a bag of $10$ marbles, $4$ are red. Two are drawn without replacement.\n\na. Find $\\Pr(\\text{first red})$. (1 mark)\n\nb. Find $\\Pr(\\text{second red} \\mid \\text{first red})$. (1 mark)\n\nc. Find $\\Pr(\\text{both red})$. (1 mark)\n\nd. Find $\\Pr(\\text{first red} \\mid \\text{second red})$. (1 mark)", marks: 4, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $\\Pr(R_1) = \\tfrac{4}{10} = 0.4$.\n\n**Step 2 (1 mark):** $\\Pr(R_2 \\mid R_1) = \\tfrac{3}{9} = \\tfrac{1}{3}$.\n\n**Step 3 (1 mark):** $\\Pr(\\text{both red}) = 0.4 \\cdot \\tfrac{1}{3} = \\tfrac{2}{15}$.\n\n**Step 4 (1 mark):** By symmetry $\\Pr(R_2) = 0.4$, so $\\Pr(R_1 \\mid R_2) = \\tfrac{2/15}{0.4} = \\tfrac{1}{3}$.", subtopicSlugs: S },
    { content: `Consider the contingency table:\n\n| | X | Y | Total |\n|---|---|---|---|\n| P | $12$ | $28$ | $40$ |\n| Q | $18$ | $42$ | $60$ |\n| Total | $30$ | $70$ | $100$ |\n\nDetermine whether $P$ and $X$ are independent. Justify.`, marks: 3, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $\\Pr(P) = 0.4$, $\\Pr(X) = 0.3$.\n\n**Step 2 (1 mark):** Product $= 0.12$; and $\\Pr(P \\cap X) = \\tfrac{12}{100} = 0.12$.\n\n**Step 3 (1 mark):** Since $\\Pr(P \\cap X) = \\Pr(P) \\Pr(X)$, the events $P$ and $X$ are independent.", subtopicSlugs: S },
  ];
  const extendedResponse: FR[] = [
    { content: "A medical test for a disease has sensitivity $0.95$ (correctly positive given disease) and specificity $0.90$ (correctly negative given no disease). The disease prevalence is $0.02$.\n\n**a.** Draw a tree diagram for the situation (describe it). (1 mark)\n\n**b.** Find $\\Pr(\\text{disease and positive})$. (2 marks)\n\n**c.** Find $\\Pr(\\text{no disease and positive})$. (2 marks)\n\n**d.** Find $\\Pr(\\text{positive})$. (1 mark)\n\n**e.** Find $\\Pr(\\text{disease} \\mid \\text{positive})$. (2 marks)\n\n**f.** Interpret the result in part (e). (1 mark)\n\n**g.** Find $\\Pr(\\text{disease} \\mid \\text{negative})$. (2 marks)", marks: 11, difficulty: "HARD", solutionContent: "**a. (1 mark)**\n\n*Step 1 (1 mark):* Branches: disease ($0.02$) / no disease ($0.98$); each leads to positive / negative with sensitivity / specificity probabilities.\n\n**b. (2 marks)**\n\n*Step 1 (1 mark):* Multiply along the branch.\n\n*Step 2 (1 mark):* $\\Pr(D \\cap +) = 0.02 \\cdot 0.95 = 0.019$.\n\n**c. (2 marks)**\n\n*Step 1 (1 mark):* $\\Pr(D') = 0.98$, $\\Pr(+ \\mid D') = 0.10$.\n\n*Step 2 (1 mark):* $\\Pr(D' \\cap +) = 0.098$.\n\n**d. (1 mark)**\n\n*Step 1 (1 mark):* $\\Pr(+) = 0.019 + 0.098 = 0.117$.\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* $\\Pr(D \\mid +) = \\tfrac{0.019}{0.117}$.\n\n*Step 2 (1 mark):* $\\approx 0.162$.\n\n**f. (1 mark)**\n\n*Step 1 (1 mark):* Even after a positive test, the probability of actually having the disease is only about $16\\%$ because the disease is rare.\n\n**g. (2 marks)**\n\n*Step 1 (1 mark):* $\\Pr(D \\cap -) = 0.02 \\cdot 0.05 = 0.001$, $\\Pr(-) = 0.001 + 0.98 \\cdot 0.90 = 0.883$.\n\n*Step 2 (1 mark):* $\\Pr(D \\mid -) = \\tfrac{0.001}{0.883} \\approx 0.00113$.", subtopicSlugs: S },
    { content: `A survey of $500$ customers classified them by age group and satisfaction level:\n\n| | Satisfied | Dissatisfied | Total |\n|---|---|---|---|\n| Under 30 | $120$ | $80$ | $200$ |\n| 30-50 | $150$ | $50$ | $200$ |\n| Over 50 | $75$ | $25$ | $100$ |\n| Total | $345$ | $155$ | $500$ |\n\n**a.** Find $\\Pr(\\text{satisfied})$. (1 mark)\n\n**b.** Find $\\Pr(\\text{satisfied} \\mid \\text{Over 50})$. (2 marks)\n\n**c.** Find $\\Pr(\\text{Under 30} \\mid \\text{dissatisfied})$. (2 marks)\n\n**d.** Determine whether the events "satisfied" and "Under 30" are independent. (3 marks)\n\n**e.** Find $\\Pr(\\text{30-50} \\cap \\text{satisfied})$. (1 mark)\n\n**f.** Given a customer is satisfied, find $\\Pr(\\text{30-50})$. (1 mark)`, marks: 10, difficulty: "HARD", solutionContent: "**a. (1 mark)**\n\n*Step 1 (1 mark):* $\\Pr(S) = \\tfrac{345}{500} = 0.69$.\n\n**b. (2 marks)**\n\n*Step 1 (1 mark):* Condition on Over 50 ($n = 100$).\n\n*Step 2 (1 mark):* $\\Pr(S \\mid \\text{Over 50}) = \\tfrac{75}{100} = 0.75$.\n\n**c. (2 marks)**\n\n*Step 1 (1 mark):* Condition on dissatisfied ($n = 155$).\n\n*Step 2 (1 mark):* $\\Pr(\\text{Under 30} \\mid D) = \\tfrac{80}{155} \\approx 0.516$.\n\n**d. (3 marks)**\n\n*Step 1 (1 mark):* $\\Pr(\\text{Under 30}) = \\tfrac{200}{500} = 0.4$.\n\n*Step 2 (1 mark):* $\\Pr(S) \\Pr(\\text{Under 30}) = 0.69 \\cdot 0.4 = 0.276$.\n\n*Step 3 (1 mark):* $\\Pr(S \\cap \\text{Under 30}) = \\tfrac{120}{500} = 0.24 \\neq 0.276$, so not independent.\n\n**e. (1 mark)**\n\n*Step 1 (1 mark):* $\\tfrac{150}{500} = 0.3$.\n\n**f. (1 mark)**\n\n*Step 1 (1 mark):* $\\tfrac{150}{345} \\approx 0.435$.", subtopicSlugs: S },
    { content: "In a factory, $60\\%$ of items come from Machine A and $40\\%$ from Machine B. The defect rate is $5\\%$ for A and $10\\%$ for B.\n\n**a.** Draw a tree diagram. Find $\\Pr(\\text{defective})$. (3 marks)\n\n**b.** Find $\\Pr(\\text{A} \\mid \\text{defective})$. (2 marks)\n\n**c.** Find $\\Pr(\\text{B} \\mid \\text{defective})$. (1 mark)\n\n**d.** Find $\\Pr(\\text{A} \\mid \\text{not defective})$. (2 marks)\n\n**e.** Interpret the comparison between $\\Pr(A)$ and $\\Pr(A \\mid \\text{defective})$. (1 mark)", marks: 9, difficulty: "HARD", solutionContent: "**a. (3 marks)**\n\n*Step 1 (1 mark):* Tree: $A (0.6)$ with defective $0.05$; $B (0.4)$ with defective $0.10$.\n\n*Step 2 (1 mark):* $\\Pr(A \\cap D) = 0.03$, $\\Pr(B \\cap D) = 0.04$.\n\n*Step 3 (1 mark):* $\\Pr(D) = 0.03 + 0.04 = 0.07$.\n\n**b. (2 marks)**\n\n*Step 1 (1 mark):* Apply Bayes.\n\n*Step 2 (1 mark):* $\\Pr(A \\mid D) = \\tfrac{0.03}{0.07} = \\tfrac{3}{7} \\approx 0.429$.\n\n**c. (1 mark)**\n\n*Step 1 (1 mark):* $\\Pr(B \\mid D) = \\tfrac{0.04}{0.07} = \\tfrac{4}{7} \\approx 0.571$.\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* $\\Pr(A \\cap D') = 0.6 \\cdot 0.95 = 0.57$, $\\Pr(D') = 0.93$.\n\n*Step 2 (1 mark):* $\\Pr(A \\mid D') = \\tfrac{0.57}{0.93} \\approx 0.613$.\n\n**e. (1 mark)**\n\n*Step 1 (1 mark):* $\\Pr(A) = 0.6$ but $\\Pr(A \\mid D) \\approx 0.429 < 0.6$, meaning defectives are relatively more likely from B.", subtopicSlugs: S },
    { content: "A student has two boxes. Box 1 has $3$ red and $2$ blue balls. Box 2 has $1$ red and $4$ blue balls. A box is selected at random (each with prob $1/2$) and a ball is drawn.\n\n**a.** Find $\\Pr(\\text{red})$. (3 marks)\n\n**b.** Given the ball is red, find $\\Pr(\\text{Box 1})$. (3 marks)\n\n**c.** Given the ball is blue, find $\\Pr(\\text{Box 2})$. (3 marks)\n\n**d.** A second ball is drawn from the same chosen box without replacement. Given the first was red, find $\\Pr(\\text{second red})$. (3 marks)", marks: 12, difficulty: "HARD", solutionContent: "**a. (3 marks)**\n\n*Step 1 (1 mark):* $\\Pr(R \\mid 1) = \\tfrac{3}{5}$ and $\\Pr(R \\mid 2) = \\tfrac{1}{5}$.\n\n*Step 2 (1 mark):* $\\Pr(R) = \\tfrac{1}{2} \\cdot \\tfrac{3}{5} + \\tfrac{1}{2} \\cdot \\tfrac{1}{5}$.\n\n*Step 3 (1 mark):* $= \\tfrac{3}{10} + \\tfrac{1}{10} = \\tfrac{4}{10} = \\tfrac{2}{5}$.\n\n**b. (3 marks)**\n\n*Step 1 (1 mark):* Bayes: $\\Pr(1 \\mid R) = \\tfrac{\\Pr(1) \\Pr(R \\mid 1)}{\\Pr(R)}$.\n\n*Step 2 (1 mark):* Numerator $= \\tfrac{1}{2} \\cdot \\tfrac{3}{5} = \\tfrac{3}{10}$.\n\n*Step 3 (1 mark):* Ratio $= \\tfrac{3/10}{2/5} = \\tfrac{3}{4}$.\n\n**c. (3 marks)**\n\n*Step 1 (1 mark):* $\\Pr(B \\mid 1) = \\tfrac{2}{5}$, $\\Pr(B \\mid 2) = \\tfrac{4}{5}$.\n\n*Step 2 (1 mark):* $\\Pr(B) = \\tfrac{1}{2} \\cdot \\tfrac{2}{5} + \\tfrac{1}{2} \\cdot \\tfrac{4}{5} = \\tfrac{6}{10} = \\tfrac{3}{5}$.\n\n*Step 3 (1 mark):* $\\Pr(2 \\mid B) = \\tfrac{(1/2)(4/5)}{3/5} = \\tfrac{4/10}{3/5} = \\tfrac{2}{3}$.\n\n**d. (3 marks)**\n\n*Step 1 (1 mark):* From part b, given first red, $\\Pr(\\text{Box 1}) = \\tfrac{3}{4}$, $\\Pr(\\text{Box 2}) = \\tfrac{1}{4}$.\n\n*Step 2 (1 mark):* $\\Pr(\\text{2nd red} \\mid \\text{1st red, Box 1}) = \\tfrac{2}{4} = \\tfrac{1}{2}$; $\\Pr(\\text{2nd red} \\mid \\text{1st red, Box 2}) = \\tfrac{0}{4} = 0$.\n\n*Step 3 (1 mark):* Weighted: $\\tfrac{3}{4} \\cdot \\tfrac{1}{2} + \\tfrac{1}{4} \\cdot 0 = \\tfrac{3}{8}$.", subtopicSlugs: S },
    { content: `Two events $A$ and $B$ satisfy $\\Pr(A) = 0.6$, $\\Pr(B) = 0.4$, and $\\Pr(A \\cup B) = 0.8$.\n\n**a.** Find $\\Pr(A \\cap B)$. (2 marks)\n\n**b.** Find $\\Pr(A \\mid B)$. (2 marks)\n\n**c.** Find $\\Pr(B \\mid A)$. (2 marks)\n\n**d.** Determine whether $A$ and $B$ are independent. (2 marks)\n\n**e.** Find $\\Pr(A \\mid B')$. (3 marks)\n\n**f.** Find $\\Pr(A' \\mid B')$. (2 marks)\n\n**g.** Two independent trials of this experiment are performed. Find the probability both yield the event $A$. (2 marks)`, marks: 15, difficulty: "HARD", solutionContent: "**a. (2 marks)**\n\n*Step 1 (1 mark):* Addition rule.\n\n*Step 2 (1 mark):* $\\Pr(A \\cap B) = 0.6 + 0.4 - 0.8 = 0.2$.\n\n**b. (2 marks)**\n\n*Step 1 (1 mark):* Formula.\n\n*Step 2 (1 mark):* $\\Pr(A \\mid B) = \\tfrac{0.2}{0.4} = 0.5$.\n\n**c. (2 marks)**\n\n*Step 1 (1 mark):* Formula.\n\n*Step 2 (1 mark):* $\\Pr(B \\mid A) = \\tfrac{0.2}{0.6} = \\tfrac{1}{3}$.\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* Check $\\Pr(A)\\Pr(B) = 0.24$.\n\n*Step 2 (1 mark):* $0.24 \\neq 0.2$, so not independent.\n\n**e. (3 marks)**\n\n*Step 1 (1 mark):* $\\Pr(B') = 0.6$.\n\n*Step 2 (1 mark):* $\\Pr(A \\cap B') = \\Pr(A) - \\Pr(A \\cap B) = 0.6 - 0.2 = 0.4$.\n\n*Step 3 (1 mark):* $\\Pr(A \\mid B') = \\tfrac{0.4}{0.6} = \\tfrac{2}{3}$.\n\n**f. (2 marks)**\n\n*Step 1 (1 mark):* $\\Pr(A' \\cap B') = 1 - \\Pr(A \\cup B) = 0.2$.\n\n*Step 2 (1 mark):* $\\Pr(A' \\mid B') = \\tfrac{0.2}{0.6} = \\tfrac{1}{3}$.\n\n**g. (2 marks)**\n\n*Step 1 (1 mark):* By independence of trials.\n\n*Step 2 (1 mark):* $\\Pr(\\text{both} A) = 0.6^2 = 0.36$.", subtopicSlugs: S },
  ];
  writeQset(OUT("conditional-probability"), { mcq, shortAnswer, extendedResponse });
}

