{
  const S = ["binomial-distribution"];
  const mcq: MCQ[] = [
    { content: "If $X \\sim \\text{Bi}(n, p)$, then $E(X)$ equals:", optionA: "$p$", optionB: "$np$", optionC: "$n(1 - p)$", optionD: "$np(1 - p)$", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Mean of binomial is $E(X) = np$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "If $X \\sim \\text{Bi}(n, p)$, then $\\text{Var}(X)$ equals:", optionA: "$np$", optionB: "$np(1 - p)$", optionC: "$n(1 - p)$", optionD: "$p(1 - p)$", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Variance of binomial is $np(1 - p)$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "For $X \\sim \\text{Bi}(5, 0.2)$, $E(X)$ equals:", optionA: "$0.5$", optionB: "$1$", optionC: "$2$", optionD: "$5$", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $E(X) = 5 \\cdot 0.2 = 1$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "For $X \\sim \\text{Bi}(10, 0.5)$, $\\text{Var}(X)$ equals:", optionA: "$2.5$", optionB: "$5$", optionC: "$10$", optionD: "$25$", correctOption: "A", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $\\text{Var}(X) = 10 \\cdot 0.5 \\cdot 0.5 = 2.5$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "For $X \\sim \\text{Bi}(4, 0.5)$, $\\Pr(X = 2)$ equals:", optionA: "$\\dfrac{1}{16}$", optionB: "$\\dfrac{3}{8}$", optionC: "$\\dfrac{1}{4}$", optionD: "$\\dfrac{1}{2}$", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $\\Pr(X = 2) = \\binom{4}{2}(0.5)^2(0.5)^2 = 6 \\cdot \\tfrac{1}{16} = \\tfrac{6}{16} = \\tfrac{3}{8}$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "A fair coin is tossed $3$ times. The probability of exactly $1$ head is:", optionA: "$\\dfrac{1}{8}$", optionB: "$\\dfrac{3}{8}$", optionC: "$\\dfrac{1}{2}$", optionD: "$\\dfrac{1}{4}$", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $\\Pr(X = 1) = \\binom{3}{1}(0.5)(0.5)^2 = 3 \\cdot \\tfrac{1}{8} = \\tfrac{3}{8}$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "For $X \\sim \\text{Bi}(n, p)$, $\\Pr(X = k)$ equals:", optionA: "$\\binom{n}{k} p^k (1 - p)^{n - k}$", optionB: "$p^k (1 - p)^{n - k}$", optionC: "$\\binom{n}{k} p^{n - k}$", optionD: "$n p^k$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Binomial pmf.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "For $X \\sim \\text{Bi}(6, 1/3)$, $E(X)$ equals:", optionA: "$1$", optionB: "$2$", optionC: "$3$", optionD: "$6$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $E(X) = 6 \\cdot \\tfrac{1}{3} = 2$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "For $X \\sim \\text{Bi}(100, 0.1)$, $\\text{SD}(X)$ equals:", optionA: "$1$", optionB: "$3$", optionC: "$9$", optionD: "$10$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $\\text{Var}(X) = 100 \\cdot 0.1 \\cdot 0.9 = 9$, so $\\text{SD}(X) = 3$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "For $X \\sim \\text{Bi}(5, 0.4)$, $\\Pr(X = 0)$ equals:", optionA: "$0.4^5$", optionB: "$0.6^5$", optionC: "$0.4 \\cdot 0.6^4$", optionD: "$1 - 0.4^5$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $\\Pr(X = 0) = (1 - p)^n = 0.6^5 \\approx 0.0778$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "The probability of rolling a $6$ in at least one of $4$ fair die rolls is:", optionA: "$\\left(\\tfrac{1}{6}\\right)^4$", optionB: "$1 - \\left(\\tfrac{5}{6}\\right)^4$", optionC: "$\\tfrac{4}{6}$", optionD: "$\\tfrac{1}{6}$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Complement.\n\n$$\\Pr(\\text{at least one 6}) = 1 - \\Pr(\\text{no 6}) = 1 - \\left(\\tfrac{5}{6}\\right)^4.$$\n\n**Answer: B**", subtopicSlugs: S },
    { content: `The pmf of $X \\sim \\text{Bi}(10, 0.3)$ is partially tabulated:\n\n| $k$ | $0$ | $1$ | $2$ | $3$ | $4$ | $5$ |\n|---|---|---|---|---|---|---|\n| $\\Pr$ | $0.028$ | $0.121$ | $0.233$ | $0.267$ | $0.200$ | $0.103$ |\n\nThe mode of $X$ is:`, optionA: "$0$", optionB: "$2$", optionC: "$3$", optionD: "$5$", correctOption: "C", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Highest probability is at $k = 3$ with $0.267$.\n\n**Answer: C**", subtopicSlugs: S },
    { content: "The probability of success is $p = 0.2$. In $10$ independent trials, the expected number of successes is:", optionA: "$1$", optionB: "$2$", optionC: "$5$", optionD: "$10$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $E(X) = 10 \\cdot 0.2 = 2$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "In a multiple choice test with $5$ options per question, a student guesses $4$ questions. The expected number correct is:", optionA: "$0.4$", optionB: "$0.8$", optionC: "$1$", optionD: "$2$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $E(X) = 4 \\cdot \\tfrac{1}{5} = 0.8$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "For $X \\sim \\text{Bi}(5, 0.6)$, $\\Pr(X = 5)$ equals:", optionA: "$0.6$", optionB: "$0.6^5$", optionC: "$0.4^5$", optionD: "$0.5$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $\\Pr(X = 5) = \\binom{5}{5} 0.6^5 0.4^0 = 0.6^5 \\approx 0.0778$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "For $X \\sim \\text{Bi}(n, p)$, as $p \\to 0.5$ with $n$ fixed, the variance:", optionA: "decreases", optionB: "increases to max", optionC: "stays constant", optionD: "goes to zero", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $p(1 - p)$ is maximised at $p = 0.5$, so variance is maximised there.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "For $X \\sim \\text{Bi}(6, 0.5)$, $\\Pr(X \\geq 4)$ equals:", optionA: "$\\dfrac{11}{32}$", optionB: "$\\dfrac{11}{64}$", optionC: "$\\dfrac{22}{64}$", optionD: "$\\dfrac{1}{2}$", correctOption: "A", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $\\Pr(X = 4) = \\binom{6}{4}/64 = 15/64$. $\\Pr(X = 5) = 6/64$. $\\Pr(X = 6) = 1/64$.\n\n**Step 2:** Sum $= 22/64 = 11/32$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "For $X \\sim \\text{Bi}(20, 0.5)$, the expected value and standard deviation are:", optionA: "$E = 10, \\text{SD} \\approx 2.24$", optionB: "$E = 10, \\text{SD} = 5$", optionC: "$E = 5, \\text{SD} = \\sqrt{5}$", optionD: "$E = 20, \\text{SD} = 4$", correctOption: "A", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $E = 10$, $\\text{Var} = 5$, $\\text{SD} = \\sqrt{5} \\approx 2.236$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "A quality control sample of $n = 20$ items has defect probability $p = 0.05$. The probability of finding no defectives is approximately:", optionA: "$0.358$", optionB: "$0.377$", optionC: "$0.599$", optionD: "$0.736$", correctOption: "A", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $\\Pr(X = 0) = 0.95^{20} \\approx 0.3585$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "For $X \\sim \\text{Bi}(10, p)$, if $E(X) = 6$, then $\\text{Var}(X)$ equals:", optionA: "$1.6$", optionB: "$2.4$", optionC: "$4$", optionD: "$6$", correctOption: "B", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $p = 0.6$, so $\\text{Var}(X) = 10 \\cdot 0.6 \\cdot 0.4 = 2.4$.\n\n**Answer: B**", subtopicSlugs: S },
  ];
  const shortAnswer: FR[] = [
    { content: "If $X \\sim \\text{Bi}(8, 0.25)$, find $E(X)$ and $\\text{Var}(X)$.", marks: 2, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $E(X) = 8 \\cdot 0.25 = 2$.\n\n**Step 2 (1 mark):** $\\text{Var}(X) = 8 \\cdot 0.25 \\cdot 0.75 = 1.5$.", subtopicSlugs: S },
    { content: "A fair coin is tossed $5$ times. Find the probability of exactly $3$ heads.", marks: 2, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $\\binom{5}{3} = 10$.\n\n**Step 2 (1 mark):** $\\Pr(X = 3) = 10 \\cdot (0.5)^3 (0.5)^2 = 10/32 = 5/16$.", subtopicSlugs: S },
    { content: "If $X \\sim \\text{Bi}(6, 0.2)$, find $\\Pr(X = 0)$ and $\\Pr(X = 1)$.", marks: 2, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $\\Pr(X = 0) = 0.8^6 \\approx 0.2621$.\n\n**Step 2 (1 mark):** $\\Pr(X = 1) = 6 \\cdot 0.2 \\cdot 0.8^5 \\approx 0.3932$.", subtopicSlugs: S },
    { content: "A fair die is rolled $5$ times. Find the probability of rolling exactly two $6$s.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $X \\sim \\text{Bi}(5, 1/6)$.\n\n**Step 2 (1 mark):** $\\Pr(X = 2) = \\binom{5}{2} (1/6)^2 (5/6)^3$.\n\n**Step 3 (1 mark):** $= 10 \\cdot \\tfrac{1}{36} \\cdot \\tfrac{125}{216} = \\tfrac{1250}{7776} \\approx 0.1608$.", subtopicSlugs: S },
    { content: "In a large bag, $30\\%$ of marbles are red. $10$ marbles are drawn with replacement. Find the probability that exactly $4$ are red.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $X \\sim \\text{Bi}(10, 0.3)$.\n\n**Step 2 (1 mark):** $\\Pr(X = 4) = \\binom{10}{4} 0.3^4 0.7^6$.\n\n**Step 3 (1 mark):** $= 210 \\cdot 0.0081 \\cdot 0.1176 \\approx 0.2001$.", subtopicSlugs: S },
    { content: "A basketball player scores with probability $p = 0.7$ per shot. He takes $5$ shots.\n\na. Find the probability of scoring all $5$. (1 mark)\n\nb. Find the expected number of scores. (1 mark)\n\nc. Find the probability of scoring at least $4$. (2 marks)", marks: 4, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $\\Pr(X = 5) = 0.7^5 \\approx 0.1681$.\n\n**Step 2 (1 mark):** $E(X) = 5 \\cdot 0.7 = 3.5$.\n\n**Step 3 (1 mark):** $\\Pr(X = 4) = \\binom{5}{4}(0.7)^4(0.3) = 5 \\cdot 0.2401 \\cdot 0.3 \\approx 0.3602$.\n\n**Step 4 (1 mark):** $\\Pr(X \\geq 4) = 0.3602 + 0.1681 \\approx 0.5283$.", subtopicSlugs: S },
    { content: "A biased coin has $\\Pr(H) = 0.6$. It is tossed $8$ times.\n\na. Find the expected number of heads. (1 mark)\n\nb. Find the standard deviation. (2 marks)", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $E(X) = 8 \\cdot 0.6 = 4.8$.\n\n**Step 2 (1 mark):** $\\text{Var}(X) = 8 \\cdot 0.6 \\cdot 0.4 = 1.92$.\n\n**Step 3 (1 mark):** $\\text{SD}(X) = \\sqrt{1.92} \\approx 1.386$.", subtopicSlugs: S },
    { content: "A machine produces items with a $5\\%$ defect rate. A sample of $20$ items is tested.\n\na. Find the probability of exactly $1$ defective. (2 marks)\n\nb. Find the expected number of defectives. (1 mark)", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $X \\sim \\text{Bi}(20, 0.05)$.\n\n**Step 2 (1 mark):** $\\Pr(X = 1) = 20 \\cdot 0.05 \\cdot 0.95^{19} \\approx 20 \\cdot 0.05 \\cdot 0.3774 \\approx 0.3774$.\n\n**Step 3 (1 mark):** $E(X) = 20 \\cdot 0.05 = 1$.", subtopicSlugs: S },
    { content: "A fair coin is tossed $10$ times.\n\na. Find the probability of exactly $5$ heads. (2 marks)\n\nb. Find the probability of at least $8$ heads. (2 marks)", marks: 4, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $\\Pr(X = 5) = \\binom{10}{5}/1024 = 252/1024$.\n\n**Step 2 (1 mark):** $\\approx 0.2461$.\n\n**Step 3 (1 mark):** $\\Pr(X \\geq 8) = (\\binom{10}{8} + \\binom{10}{9} + \\binom{10}{10})/1024 = (45 + 10 + 1)/1024$.\n\n**Step 4 (1 mark):** $= 56/1024 \\approx 0.0547$.", subtopicSlugs: S },
    { content: "In a survey, $40\\%$ of people prefer tea. In a random sample of $15$ people, find the probability that between $5$ and $7$ inclusive prefer tea. Use pmf values $\\Pr(X=5) \\approx 0.1859$, $\\Pr(X=6) \\approx 0.2066$, $\\Pr(X=7) \\approx 0.1771$.", marks: 3, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** Use given probabilities.\n\n**Step 2 (1 mark):** Sum.\n\n$$0.1859 + 0.2066 + 0.1771.$$\n\n**Step 3 (1 mark):** $\\approx 0.5696$.", subtopicSlugs: S },
  ];
  const extendedResponse: FR[] = [
    { content: "A fair coin is tossed $10$ times. Let $X$ be the number of heads.\n\n**a.** State the distribution of $X$. (1 mark)\n\n**b.** Find $E(X)$ and $\\text{Var}(X)$. (2 marks)\n\n**c.** Find $\\Pr(X = 5)$. (2 marks)\n\n**d.** Find $\\Pr(X \\geq 8)$. (3 marks)\n\n**e.** Find $\\Pr(X \\leq 2)$. (2 marks)\n\n**f.** State $\\text{SD}(X)$. (1 mark)", marks: 11, difficulty: "HARD", solutionContent: "**a. (1 mark)**\n\n*Step 1 (1 mark):* $X \\sim \\text{Bi}(10, 0.5)$.\n\n**b. (2 marks)**\n\n*Step 1 (1 mark):* $E(X) = 10 \\cdot 0.5 = 5$.\n\n*Step 2 (1 mark):* $\\text{Var}(X) = 10 \\cdot 0.5 \\cdot 0.5 = 2.5$.\n\n**c. (2 marks)**\n\n*Step 1 (1 mark):* $\\binom{10}{5} = 252$.\n\n*Step 2 (1 mark):* $\\Pr(X = 5) = 252/1024 \\approx 0.2461$.\n\n**d. (3 marks)**\n\n*Step 1 (1 mark):* $\\binom{10}{8} = 45$, $\\binom{10}{9} = 10$, $\\binom{10}{10} = 1$.\n\n*Step 2 (1 mark):* Sum numerators $= 56$.\n\n*Step 3 (1 mark):* $\\Pr(X \\geq 8) = 56/1024 \\approx 0.0547$.\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* By symmetry, $\\Pr(X \\leq 2) = \\Pr(X \\geq 8)$.\n\n*Step 2 (1 mark):* $\\approx 0.0547$.\n\n**f. (1 mark)**\n\n*Step 1 (1 mark):* $\\text{SD}(X) = \\sqrt{2.5} \\approx 1.581$.", subtopicSlugs: S },
    { content: "A machine produces items with a defect rate of $10\\%$. A random sample of $n = 12$ items is tested.\n\n**a.** State the distribution of the number of defectives $X$. (1 mark)\n\n**b.** Find $E(X)$ and $\\text{SD}(X)$. (3 marks)\n\n**c.** Find $\\Pr(X = 0)$. (2 marks)\n\n**d.** Find $\\Pr(X = 1)$. (2 marks)\n\n**e.** Find $\\Pr(X \\leq 2)$ using the formulas. (3 marks)\n\n**f.** A batch is rejected if $X \\geq 3$. Find $\\Pr(\\text{rejected})$. (1 mark)", marks: 12, difficulty: "HARD", solutionContent: "**a. (1 mark)**\n\n*Step 1 (1 mark):* $X \\sim \\text{Bi}(12, 0.1)$.\n\n**b. (3 marks)**\n\n*Step 1 (1 mark):* $E(X) = 12 \\cdot 0.1 = 1.2$.\n\n*Step 2 (1 mark):* $\\text{Var}(X) = 12 \\cdot 0.1 \\cdot 0.9 = 1.08$.\n\n*Step 3 (1 mark):* $\\text{SD}(X) = \\sqrt{1.08} \\approx 1.039$.\n\n**c. (2 marks)**\n\n*Step 1 (1 mark):* $\\Pr(X = 0) = 0.9^{12}$.\n\n*Step 2 (1 mark):* $\\approx 0.2824$.\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* $\\Pr(X = 1) = 12 \\cdot 0.1 \\cdot 0.9^{11}$.\n\n*Step 2 (1 mark):* $\\approx 12 \\cdot 0.1 \\cdot 0.3138 \\approx 0.3766$.\n\n**e. (3 marks)**\n\n*Step 1 (1 mark):* $\\Pr(X = 2) = \\binom{12}{2}(0.1)^2(0.9)^{10} = 66 \\cdot 0.01 \\cdot 0.3487 \\approx 0.2301$.\n\n*Step 2 (1 mark):* $\\Pr(X \\leq 2) = 0.2824 + 0.3766 + 0.2301$.\n\n*Step 3 (1 mark):* $\\approx 0.8891$.\n\n**f. (1 mark)**\n\n*Step 1 (1 mark):* $\\Pr(X \\geq 3) = 1 - 0.8891 \\approx 0.1109$.", subtopicSlugs: S },
    { content: "In an archery contest, an archer hits the bullseye with probability $p = 0.4$ on each shot.\n\n**a.** He shoots $6$ times. State the distribution of hits $X$. (1 mark)\n\n**b.** Find $E(X)$. (1 mark)\n\n**c.** Find $\\Pr(X = 3)$. (2 marks)\n\n**d.** Find $\\Pr(X \\geq 4)$. (3 marks)\n\n**e.** Find the probability of exactly $2$ hits in the first $3$ shots. (2 marks)", marks: 9, difficulty: "HARD", solutionContent: "**a. (1 mark)**\n\n*Step 1 (1 mark):* $X \\sim \\text{Bi}(6, 0.4)$.\n\n**b. (1 mark)**\n\n*Step 1 (1 mark):* $E(X) = 6 \\cdot 0.4 = 2.4$.\n\n**c. (2 marks)**\n\n*Step 1 (1 mark):* $\\binom{6}{3} = 20$.\n\n*Step 2 (1 mark):* $\\Pr(X = 3) = 20 \\cdot 0.4^3 \\cdot 0.6^3 = 20 \\cdot 0.064 \\cdot 0.216 \\approx 0.2765$.\n\n**d. (3 marks)**\n\n*Step 1 (1 mark):* $\\Pr(X = 4) = \\binom{6}{4} 0.4^4 \\cdot 0.6^2 = 15 \\cdot 0.0256 \\cdot 0.36 \\approx 0.1382$.\n\n*Step 2 (1 mark):* $\\Pr(X = 5) = \\binom{6}{5} 0.4^5 \\cdot 0.6 = 6 \\cdot 0.01024 \\cdot 0.6 \\approx 0.0369$, and $\\Pr(X = 6) = 0.4^6 \\approx 0.0041$.\n\n*Step 3 (1 mark):* $\\Pr(X \\geq 4) \\approx 0.1382 + 0.0369 + 0.0041 \\approx 0.1792$.\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* Let $Y \\sim \\text{Bi}(3, 0.4)$. $\\Pr(Y = 2) = \\binom{3}{2} 0.4^2 \\cdot 0.6 = 3 \\cdot 0.16 \\cdot 0.6$.\n\n*Step 2 (1 mark):* $= 0.288$.", subtopicSlugs: S },
    { content: "Students answer a multiple-choice test with $10$ questions, $4$ options each.\n\n**a.** Guessing, find the probability of zero correct. (2 marks)\n\n**b.** Find the probability of exactly $3$ correct. (3 marks)\n\n**c.** Find $E(X)$ and $\\text{Var}(X)$ for the number correct. (3 marks)\n\n**d.** Find $\\Pr(X \\geq 1)$. (2 marks)\n\n**e.** What is the most likely number of correct guesses (mode)? Justify. (2 marks)", marks: 12, difficulty: "HARD", solutionContent: "**a. (2 marks)**\n\n*Step 1 (1 mark):* $p = 0.25$, $n = 10$, so $\\Pr(X = 0) = 0.75^{10}$.\n\n*Step 2 (1 mark):* $\\approx 0.0563$.\n\n**b. (3 marks)**\n\n*Step 1 (1 mark):* $\\binom{10}{3} = 120$.\n\n*Step 2 (1 mark):* $\\Pr(X = 3) = 120 \\cdot 0.25^3 \\cdot 0.75^7$.\n\n*Step 3 (1 mark):* $= 120 \\cdot 0.015625 \\cdot 0.1335 \\approx 0.2503$.\n\n**c. (3 marks)**\n\n*Step 1 (1 mark):* $E(X) = 10 \\cdot 0.25 = 2.5$.\n\n*Step 2 (1 mark):* $\\text{Var}(X) = 10 \\cdot 0.25 \\cdot 0.75 = 1.875$.\n\n*Step 3 (1 mark):* $\\text{SD}(X) \\approx 1.369$.\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* $\\Pr(X \\geq 1) = 1 - \\Pr(X = 0) = 1 - 0.0563$.\n\n*Step 2 (1 mark):* $\\approx 0.9437$.\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* The mode of $\\text{Bi}(n, p)$ is typically $\\lfloor (n+1)p \\rfloor = \\lfloor 2.75 \\rfloor = 2$.\n\n*Step 2 (1 mark):* So the most likely number correct is $2$.", subtopicSlugs: S },
    { content: "A store claims that $80\\%$ of customers are satisfied. A random sample of $n = 15$ customers is surveyed. Let $X$ be the number satisfied.\n\n**a.** State the distribution of $X$. (1 mark)\n\n**b.** Find $E(X)$ and $\\text{Var}(X)$. (2 marks)\n\n**c.** Find $\\Pr(X = 15)$. (2 marks)\n\n**d.** Find $\\Pr(X \\leq 10)$. (3 marks — use $\\Pr(X = 0), \\ldots, \\Pr(X = 10)$ sums $\\approx 0.0611$) (3 marks)\n\n**e.** If only $8$ of the $15$ are satisfied, does this cast doubt on the store's claim? Justify briefly. (2 marks)\n\n**f.** Find $\\Pr(X \\geq 12)$ using $\\Pr(X = 12) \\approx 0.2501$, $\\Pr(X = 13) \\approx 0.2309$, $\\Pr(X = 14) \\approx 0.1319$, $\\Pr(X = 15) \\approx 0.0352$. (2 marks)\n\n**g.** Interpret part (b) in context. (1 mark)\n\n**h.** State the standard deviation numerically. (2 marks)", marks: 15, difficulty: "HARD", solutionContent: "**a. (1 mark)**\n\n*Step 1 (1 mark):* $X \\sim \\text{Bi}(15, 0.8)$.\n\n**b. (2 marks)**\n\n*Step 1 (1 mark):* $E(X) = 15 \\cdot 0.8 = 12$.\n\n*Step 2 (1 mark):* $\\text{Var}(X) = 15 \\cdot 0.8 \\cdot 0.2 = 2.4$.\n\n**c. (2 marks)**\n\n*Step 1 (1 mark):* $\\Pr(X = 15) = 0.8^{15}$.\n\n*Step 2 (1 mark):* $\\approx 0.0352$.\n\n**d. (3 marks)**\n\n*Step 1 (1 mark):* Use the given cumulative value.\n\n*Step 2 (1 mark):* $\\Pr(X \\leq 10) \\approx 0.0611$.\n\n*Step 3 (1 mark):* This means about $6.1\\%$ of samples would have $\\leq 10$ satisfied if the $80\\%$ claim is true.\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* $E(X) = 12$, observed $8$ is well below this.\n\n*Step 2 (1 mark):* Since $\\Pr(X \\leq 10) \\approx 6\\%$ is small and $8 < 10$, the observation is unlikely if the claim holds — this casts doubt on the claim.\n\n**f. (2 marks)**\n\n*Step 1 (1 mark):* $\\Pr(X \\geq 12) = 0.2501 + 0.2309 + 0.1319 + 0.0352$.\n\n*Step 2 (1 mark):* $\\approx 0.6481$.\n\n**g. (1 mark)**\n\n*Step 1 (1 mark):* On average $12$ of the $15$ customers would be satisfied, with variance $2.4$.\n\n**h. (2 marks)**\n\n*Step 1 (1 mark):* $\\text{SD}(X) = \\sqrt{2.4}$.\n\n*Step 2 (1 mark):* $\\approx 1.549$.", subtopicSlugs: S },
  ];
  writeQset(OUT("binomial-distribution"), { mcq, shortAnswer, extendedResponse });
}

