// SAMPLE PROPORTIONS AND SAMPLING
// ══════════════════════════════════════════════════════════════════════════
{
  const S = ["sample-proportions-and-sampling"];
  const normalPdf = (mu: number, sigma: number) => (x: number) =>
    (1 / (sigma * Math.sqrt(2 * Math.PI))) *
    Math.exp(-0.5 * Math.pow((x - mu) / sigma, 2));
  const mcq: MCQ[] = [
    { content: "The sample proportion $\\hat{p}$ from a sample of $n$ with $X$ successes is:", optionA: "$X$", optionB: "$\\dfrac{X}{n}$", optionC: "$n - X$", optionD: "$np$", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $\\hat{p} = X/n$ by definition.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "The mean of the sampling distribution of $\\hat{p}$ is:", optionA: "$n$", optionB: "$p$", optionC: "$np$", optionD: "$\\dfrac{p}{n}$", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $E(\\hat{p}) = p$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "The standard deviation of $\\hat{p}$ (for large $n$) is:", optionA: "$\\dfrac{p}{n}$", optionB: "$\\sqrt{\\dfrac{p(1-p)}{n}}$", optionC: "$\\sqrt{np(1-p)}$", optionD: "$p(1-p)$", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Standard deviation of $\\hat{p}$.\n\n$$\\text{SD}(\\hat{p}) = \\sqrt{\\tfrac{p(1 - p)}{n}}.$$\n\n**Answer: B**", subtopicSlugs: S },
    { content: "A sample of $200$ gives $70$ successes. The sample proportion is:", optionA: "$0.07$", optionB: "$0.25$", optionC: "$0.35$", optionD: "$0.70$", correctOption: "C", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $\\hat{p} = 70/200 = 0.35$.\n\n**Answer: C**", subtopicSlugs: S },
    { content: "As sample size $n$ increases, the spread of the sampling distribution of $\\hat{p}$:", optionA: "increases", optionB: "decreases", optionC: "stays the same", optionD: "doubles", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** SD of $\\hat{p}$ is proportional to $1/\\sqrt{n}$, so decreases with larger $n$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "For $p = 0.5$ and $n = 100$, the standard deviation of $\\hat{p}$ is:", optionA: "$0.005$", optionB: "$0.025$", optionC: "$0.05$", optionD: "$0.5$", correctOption: "C", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $\\sqrt{0.5 \\cdot 0.5 / 100} = \\sqrt{0.0025} = 0.05$.\n\n**Answer: C**", subtopicSlugs: S },
    { content: "The sampling distribution of $\\hat{p}$ is approximately normal for large $n$. This is a consequence of:", optionA: "the law of large numbers", optionB: "the central limit theorem", optionC: "Bayes' theorem", optionD: "the binomial formula", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** The central limit theorem.\n\n**Answer: B**", subtopicSlugs: S },
    { content: `The sampling distribution of $\\hat{p}$ with $p = 0.4$, $n = 100$ is shown.\n\n${graphImage(normalPdf(0.4, Math.sqrt(0.4 * 0.6 / 100)), { xMin: 0.2, xMax: 0.6, yMin: 0, yMax: 9 }, "Sampling distribution of p-hat")}\n\nThe mean of this distribution is:`, optionA: "$0.2$", optionB: "$0.4$", optionC: "$0.6$", optionD: "$1.0$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $E(\\hat{p}) = p = 0.4$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "For $p = 0.3$ and $n = 300$, the standard deviation of $\\hat{p}$ is approximately:", optionA: "$0.0147$", optionB: "$0.0265$", optionC: "$0.0700$", optionD: "$0.2100$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $\\sqrt{0.3 \\cdot 0.7 / 300} = \\sqrt{0.21/300} = \\sqrt{0.0007} \\approx 0.0265$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "For $p = 0.5$ and $n = 400$, find $\\Pr(\\hat{p} > 0.55)$, using $\\Pr(Z < 2) = 0.9772$.", optionA: "$0.0228$", optionB: "$0.1587$", optionC: "$0.4772$", optionD: "$0.9772$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** SD $= \\sqrt{0.25/400} = 0.025$. $Z = (0.55 - 0.5)/0.025 = 2$.\n\n$$\\Pr(Z > 2) = 0.0228.$$\n\n**Answer: A**", subtopicSlugs: S },
    { content: "The standard error of $\\hat{p}$ is useful for:", optionA: "computing the mean", optionB: "constructing confidence intervals", optionC: "finding the mode", optionD: "computing $np$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Standard error is used for CIs and hypothesis tests.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "To halve the standard deviation of $\\hat{p}$, the sample size must be:", optionA: "halved", optionB: "doubled", optionC: "quadrupled", optionD: "unchanged", correctOption: "C", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** SD $\\propto 1/\\sqrt{n}$, so to halve SD multiply $n$ by $4$.\n\n**Answer: C**", subtopicSlugs: S },
    { content: `The table gives properties of the sampling distribution of $\\hat{p}$ for various $n$ when $p = 0.3$.\n\n| $n$ | Mean | SD |\n|---|---|---|\n| $50$ | $0.3$ | $0.0648$ |\n| $100$ | $0.3$ | $0.0458$ |\n| $400$ | $0.3$ | $0.0229$ |\n| $1600$ | $0.3$ | $0.0115$ |\n\nThe ratio SD($n=400$) / SD($n=100$) is closest to:`, optionA: "$\\dfrac{1}{2}$", optionB: "$\\dfrac{1}{4}$", optionC: "$\\dfrac{1}{\\sqrt{2}}$", optionD: "$2$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $0.0229/0.0458 = 0.5 = 1/2$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "The sample proportion $\\hat{p}$ is a point estimate of:", optionA: "$\\mu$", optionB: "$p$", optionC: "$np$", optionD: "$\\sigma$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $\\hat{p}$ estimates the population proportion $p$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "Select a random sample of $n = 1$ from a Bernoulli$(p)$ population. Then $\\hat{p}$ takes values:", optionA: "only $p$", optionB: "only $0$ or $1$", optionC: "any value in $(0, 1)$", optionD: "only $0$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** With $n = 1$, $\\hat{p} = 0$ or $1$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "For $p = 0.2$, $n = 100$, the sample proportion has approximately which distribution?", optionA: "$N(0.2, 0.04)$", optionB: "$N(0.2, 0.0016)$", optionC: "$N(0.2, 0.2)$", optionD: "$N(0.5, 0.5)$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Variance $= p(1 - p)/n = 0.2 \\cdot 0.8 / 100 = 0.0016$. Mean $= 0.2$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "A survey finds $\\hat{p} = 0.52$ from $n = 625$. A $95\\%$ CI for $p$ has margin of error closest to:", optionA: "$0.02$", optionB: "$0.04$", optionC: "$0.06$", optionD: "$0.08$", correctOption: "B", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** SE $= \\sqrt{0.52 \\cdot 0.48 / 625} \\approx 0.02$.\n\n**Step 2:** Margin $= 1.96 \\cdot 0.02 \\approx 0.04$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "For $p = 0.5$, $n = 100$, find $\\Pr(0.45 < \\hat{p} < 0.55)$ using $\\Pr(Z < 1) = 0.8413$.", optionA: "$0.1587$", optionB: "$0.6826$", optionC: "$0.8413$", optionD: "$0.9544$", correctOption: "B", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** SD $= 0.05$. $Z_1 = -1$, $Z_2 = 1$.\n\n**Step 2:** $\\Pr(-1 < Z < 1) = 2(0.8413) - 1 = 0.6826$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "Sampling with replacement from a population of $1000$ with $p = 0.4$. Taking a sample of $n = 50$, the variance of $\\hat{p}$ is:", optionA: "$0.0048$", optionB: "$0.0096$", optionC: "$0.0200$", optionD: "$0.2400$", correctOption: "A", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** Var $= 0.4 \\cdot 0.6 / 50 = 0.24/50 = 0.0048$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "If $X \\sim \\text{Bi}(n, p)$ and $\\hat{p} = X/n$, then $\\text{Var}(\\hat{p})$ equals:", optionA: "$np(1 - p)$", optionB: "$\\dfrac{np(1 - p)}{n}$", optionC: "$\\dfrac{p(1 - p)}{n}$", optionD: "$p(1 - p)$", correctOption: "C", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $\\text{Var}(\\hat{p}) = \\text{Var}(X)/n^2 = np(1 - p)/n^2 = p(1 - p)/n$.\n\n**Answer: C**", subtopicSlugs: S },
  ];
  const shortAnswer: FR[] = [
    { content: "A sample of $n = 400$ gives $160$ successes. Find $\\hat{p}$.", marks: 2, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Divide.\n\n$$\\hat{p} = \\tfrac{160}{400}.$$\n\n**Step 2 (1 mark):** $= 0.4$.", subtopicSlugs: S },
    { content: "State the mean and standard deviation of $\\hat{p}$ for a random sample of size $n = 200$ from a population with $p = 0.5$.", marks: 2, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Mean $= p = 0.5$.\n\n**Step 2 (1 mark):** SD $= \\sqrt{0.25/200} = \\sqrt{0.00125} \\approx 0.0354$.", subtopicSlugs: S },
    { content: "For $p = 0.3$ and $n = 300$, find the standard deviation of $\\hat{p}$.", marks: 2, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** SD $= \\sqrt{0.3 \\cdot 0.7 / 300}$.\n\n**Step 2 (1 mark):** $= \\sqrt{0.0007} \\approx 0.0265$.", subtopicSlugs: S },
    { content: "For $p = 0.4$ and $n = 100$, find $\\Pr(\\hat{p} > 0.5)$ using $\\Pr(Z < 2.04) \\approx 0.9793$.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** SD $= \\sqrt{0.4 \\cdot 0.6 / 100} = 0.04899$.\n\n**Step 2 (1 mark):** $Z = (0.5 - 0.4)/0.04899 \\approx 2.04$.\n\n**Step 3 (1 mark):** $\\Pr(\\hat{p} > 0.5) = 1 - 0.9793 = 0.0207$.", subtopicSlugs: S },
    { content: "A survey of $n = 2500$ voters finds $\\hat{p} = 0.52$.\n\na. State the mean and approximate standard deviation of $\\hat{p}$. (2 marks)\n\nb. Construct a $95\\%$ CI for $p$. (2 marks)", marks: 4, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Mean $= p$ estimated by $0.52$.\n\n**Step 2 (1 mark):** SE $= \\sqrt{0.52 \\cdot 0.48 / 2500} \\approx 0.00999$.\n\n**Step 3 (1 mark):** Margin $= 1.96 \\cdot 0.00999 \\approx 0.0196$.\n\n**Step 4 (1 mark):** CI $\\approx (0.500, 0.540)$.", subtopicSlugs: S },
    { content: "For $p = 0.7$ and $n = 196$, find the SD of $\\hat{p}$. Use $\\Pr(Z < 1) = 0.8413$ to find $\\Pr(\\hat{p} < 0.7 + \\text{SD})$.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** SD $= \\sqrt{0.7 \\cdot 0.3 / 196} = \\sqrt{0.21/196} \\approx 0.0327$.\n\n**Step 2 (1 mark):** $\\Pr(\\hat{p} < 0.7 + \\text{SD}) = \\Pr(Z < 1)$.\n\n**Step 3 (1 mark):** $= 0.8413$.", subtopicSlugs: S },
    { content: "Explain why the sampling distribution of $\\hat{p}$ is approximately normal for large $n$.", marks: 2, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** By the central limit theorem.\n\n**Step 2 (1 mark):** For large $n$ (typically $np \\geq 10$ and $n(1 - p) \\geq 10$), the distribution of $\\hat{p}$ is approximately $N(p, p(1 - p)/n)$.", subtopicSlugs: S },
    { content: "A fair coin is tossed $100$ times. Let $\\hat{p}$ be the proportion of heads.\n\na. State mean and SD of $\\hat{p}$. (2 marks)\n\nb. Find $\\Pr(0.4 \\leq \\hat{p} \\leq 0.6)$ using $\\Pr(Z < 2) = 0.9772$. (2 marks)", marks: 4, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Mean $= 0.5$.\n\n**Step 2 (1 mark):** SD $= \\sqrt{0.25/100} = 0.05$.\n\n**Step 3 (1 mark):** $Z_1 = -2$, $Z_2 = 2$. $\\Pr(-2 < Z < 2) = 2(0.9772) - 1$.\n\n**Step 4 (1 mark):** $= 0.9544$.", subtopicSlugs: S },
    { content: "A random sample of $n = 50$ is taken from a population with $p = 0.1$. Determine whether the normal approximation to the sampling distribution of $\\hat{p}$ is appropriate.", marks: 3, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** Check $np = 5$.\n\n**Step 2 (1 mark):** $n(1 - p) = 45$.\n\n**Step 3 (1 mark):** Since $np = 5 < 10$, the normal approximation is not appropriate; a larger sample is needed.", subtopicSlugs: S },
    { content: "A company claims $80\\%$ customer satisfaction. A sample of $n = 400$ customers has $\\hat{p} = 0.75$.\n\na. State the expected mean and SD of $\\hat{p}$ under the claim. (2 marks)\n\nb. Compute the $z$-score. (1 mark)\n\nc. Comment on whether the result is consistent with the claim. (1 mark)", marks: 4, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** Mean $= 0.8$.\n\n**Step 2 (1 mark):** SD $= \\sqrt{0.8 \\cdot 0.2 / 400} = \\sqrt{0.0004} = 0.02$.\n\n**Step 3 (1 mark):** $Z = (0.75 - 0.8)/0.02 = -2.5$.\n\n**Step 4 (1 mark):** Since $|Z| = 2.5$ is large (corresponds to tail probability $\\approx 0.006$), the observed $\\hat{p}$ is inconsistent with the $80\\%$ claim.", subtopicSlugs: S },
  ];
  const extendedResponse: FR[] = [
    { content: "In a population, the true proportion of left-handed people is $p = 0.1$. A random sample of $n = 400$ is taken.\n\n**a.** State the mean of $\\hat{p}$. (1 mark)\n\n**b.** Compute the SD of $\\hat{p}$. (2 marks)\n\n**c.** Verify that the normal approximation is appropriate. (2 marks)\n\n**d.** Find $\\Pr(\\hat{p} > 0.115)$, using $\\Pr(Z < 1) = 0.8413$. (3 marks)\n\n**e.** Find $\\Pr(0.085 < \\hat{p} < 0.115)$, using $\\Pr(Z < 1) = 0.8413$. (2 marks)\n\n**f.** In a new sample of $n = 1600$, state the new SD. (1 mark)", marks: 11, difficulty: "HARD", solutionContent: "**a. (1 mark)**\n\n*Step 1 (1 mark):* Mean $= p = 0.1$.\n\n**b. (2 marks)**\n\n*Step 1 (1 mark):* SD $= \\sqrt{0.1 \\cdot 0.9 / 400}$.\n\n*Step 2 (1 mark):* $= \\sqrt{0.000225} = 0.015$.\n\n**c. (2 marks)**\n\n*Step 1 (1 mark):* $np = 40 \\geq 10$.\n\n*Step 2 (1 mark):* $n(1 - p) = 360 \\geq 10$, so normal approximation is appropriate.\n\n**d. (3 marks)**\n\n*Step 1 (1 mark):* Standardise: $Z = (0.115 - 0.1)/0.015 = 1$.\n\n*Step 2 (1 mark):* $\\Pr(Z > 1) = 1 - 0.8413$.\n\n*Step 3 (1 mark):* $= 0.1587$.\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* $Z_1 = -1, Z_2 = 1$.\n\n*Step 2 (1 mark):* $\\Pr(-1 < Z < 1) = 2(0.8413) - 1 = 0.6826$.\n\n**f. (1 mark)**\n\n*Step 1 (1 mark):* SD $= \\sqrt{0.09/1600} = 0.0075$ (halved from $0.015$ as $n$ quadrupled).", subtopicSlugs: S },
    { content: "A manufacturer produces items with a $4\\%$ defect rate. A random sample of $n = 100$ items is inspected.\n\n**a.** State the mean of $\\hat{p}$ and show the SD is $\\sqrt{0.0384/100}$. (2 marks)\n\n**b.** Compute the SD numerically. (1 mark)\n\n**c.** Discuss whether the normal approximation is appropriate. (2 marks)\n\n**d.** Find $\\Pr(\\hat{p} > 0.06)$, using $\\Pr(Z < 1.02) \\approx 0.8461$. (2 marks)\n\n**e.** In a sample of $400$, state the new SD and comment. (2 marks)\n\n**f.** Use the $400$-sample SD and $\\Pr(Z < 2) = 0.9772$ to find $\\Pr(\\hat{p} > 0.06)$. (2 marks)", marks: 11, difficulty: "HARD", solutionContent: "**a. (2 marks)**\n\n*Step 1 (1 mark):* Mean $= 0.04$.\n\n*Step 2 (1 mark):* $\\text{SD} = \\sqrt{p(1-p)/n} = \\sqrt{0.04 \\cdot 0.96 / 100} = \\sqrt{0.000384}$.\n\n**b. (1 mark)**\n\n*Step 1 (1 mark):* $\\approx 0.0196$.\n\n**c. (2 marks)**\n\n*Step 1 (1 mark):* $np = 4 < 10$.\n\n*Step 2 (1 mark):* Normal approximation is marginal/not ideal; binomial should be used for accurate calculation.\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* $Z = (0.06 - 0.04)/0.0196 \\approx 1.02$.\n\n*Step 2 (1 mark):* $\\Pr(\\hat{p} > 0.06) \\approx 1 - 0.8461 = 0.1539$.\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* New SD $= \\sqrt{0.0384/400} \\approx 0.0098$.\n\n*Step 2 (1 mark):* This is half of the old SD (as expected, since $n$ quadrupled).\n\n**f. (2 marks)**\n\n*Step 1 (1 mark):* $Z = (0.06 - 0.04)/0.0098 \\approx 2.04 \\approx 2$.\n\n*Step 2 (1 mark):* $\\Pr(\\hat{p} > 0.06) \\approx 1 - 0.9772 = 0.0228$.", subtopicSlugs: S },
    { content: "A poll aims to estimate the proportion of people who support a policy. The true $p = 0.5$.\n\n**a.** A sample of $n = 100$ is taken. State the mean and SD of $\\hat{p}$. (2 marks)\n\n**b.** Find $\\Pr(\\hat{p} > 0.55)$, using $\\Pr(Z < 1) = 0.8413$. (2 marks)\n\n**c.** Find $\\Pr(0.45 < \\hat{p} < 0.55)$. (2 marks)\n\n**d.** What is the minimum sample size so that the SD of $\\hat{p}$ is at most $0.02$? (2 marks)\n\n**e.** Construct a $95\\%$ CI for $p$ if a sample of $625$ gives $\\hat{p} = 0.48$. (2 marks)", marks: 10, difficulty: "HARD", solutionContent: "**a. (2 marks)**\n\n*Step 1 (1 mark):* Mean $= 0.5$.\n\n*Step 2 (1 mark):* SD $= \\sqrt{0.25/100} = 0.05$.\n\n**b. (2 marks)**\n\n*Step 1 (1 mark):* $Z = 1$.\n\n*Step 2 (1 mark):* $\\Pr(Z > 1) = 1 - 0.8413 = 0.1587$.\n\n**c. (2 marks)**\n\n*Step 1 (1 mark):* $Z_1 = -1, Z_2 = 1$.\n\n*Step 2 (1 mark):* $\\Pr(-1 < Z < 1) = 0.6826$.\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* Require $\\sqrt{0.25/n} \\leq 0.02$, so $n \\geq 0.25/0.0004$.\n\n*Step 2 (1 mark):* $n \\geq 625$.\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* SE $= \\sqrt{0.48 \\cdot 0.52 / 625} \\approx 0.01998$.\n\n*Step 2 (1 mark):* Margin $= 1.96 \\cdot 0.01998 \\approx 0.0392$, so CI $\\approx (0.441, 0.519)$.", subtopicSlugs: S },
    { content: "A coin is suspected biased. It is tossed $n = 400$ times and lands heads $220$ times.\n\n**a.** Compute $\\hat{p}$. (1 mark)\n\n**b.** Assuming $p = 0.5$, state the mean and SD of $\\hat{p}$. (2 marks)\n\n**c.** Compute the $z$-score for the observed $\\hat{p}$. (2 marks)\n\n**d.** Using $\\Pr(Z < 2) = 0.9772$, find $\\Pr(\\hat{p} \\geq 0.55)$. (2 marks)\n\n**e.** Interpret the result: does the outcome provide evidence the coin is biased toward heads? (2 marks)\n\n**f.** Construct a $95\\%$ CI for the true $p$. (2 marks)\n\n**g.** Does your CI support the claim $p = 0.5$? (1 mark)", marks: 12, difficulty: "HARD", solutionContent: "**a. (1 mark)**\n\n*Step 1 (1 mark):* $\\hat{p} = 220/400 = 0.55$.\n\n**b. (2 marks)**\n\n*Step 1 (1 mark):* Mean $= 0.5$.\n\n*Step 2 (1 mark):* SD $= \\sqrt{0.25/400} = 0.025$.\n\n**c. (2 marks)**\n\n*Step 1 (1 mark):* $Z = (0.55 - 0.5)/0.025$.\n\n*Step 2 (1 mark):* $= 2$.\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* $\\Pr(Z > 2) = 1 - 0.9772$.\n\n*Step 2 (1 mark):* $= 0.0228$.\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* The observed $\\hat{p} = 0.55$ is $2$ SDs above $0.5$, tail probability $\\approx 2\\%$.\n\n*Step 2 (1 mark):* This is unlikely under a fair coin, providing some evidence of bias toward heads.\n\n**f. (2 marks)**\n\n*Step 1 (1 mark):* SE $= \\sqrt{0.55 \\cdot 0.45 / 400} \\approx 0.02487$.\n\n*Step 2 (1 mark):* Margin $= 1.96 \\cdot 0.02487 \\approx 0.0488$, so CI $\\approx (0.501, 0.599)$.\n\n**g. (1 mark)**\n\n*Step 1 (1 mark):* $0.5 \\notin (0.501, 0.599)$, so the CI does not support $p = 0.5$.", subtopicSlugs: S },
    { content: "In a state, the true proportion of households owning a cat is unknown. A pilot sample of $n = 100$ gives $\\hat{p} = 0.35$.\n\n**a.** State the point estimate for $p$. (1 mark)\n\n**b.** Compute the estimated SD of $\\hat{p}$. (2 marks)\n\n**c.** Construct a $95\\%$ CI for $p$. (2 marks)\n\n**d.** Determine the sample size needed for margin of error at most $0.03$ at $95\\%$ confidence, using $\\hat{p} = 0.35$. (3 marks)\n\n**e.** Determine the sample size needed using the conservative $\\hat{p} = 0.5$. (2 marks)\n\n**f.** Explain why the conservative choice is sometimes preferred. (1 mark)\n\n**g.** A follow-up sample of $n = 900$ gives $\\hat{p} = 0.33$. Construct the new $95\\%$ CI. (2 marks)\n\n**h.** Compare the widths of the two CIs. (2 marks)", marks: 15, difficulty: "HARD", solutionContent: "**a. (1 mark)**\n\n*Step 1 (1 mark):* $\\hat{p} = 0.35$.\n\n**b. (2 marks)**\n\n*Step 1 (1 mark):* SE $= \\sqrt{0.35 \\cdot 0.65 / 100}$.\n\n*Step 2 (1 mark):* $\\approx 0.0477$.\n\n**c. (2 marks)**\n\n*Step 1 (1 mark):* Margin $= 1.96 \\cdot 0.0477 \\approx 0.0935$.\n\n*Step 2 (1 mark):* CI $\\approx (0.257, 0.443)$.\n\n**d. (3 marks)**\n\n*Step 1 (1 mark):* Require $1.96 \\sqrt{0.35 \\cdot 0.65 / n} \\leq 0.03$.\n\n*Step 2 (1 mark):* $n \\geq \\tfrac{1.96^2 \\cdot 0.2275}{0.0009}$.\n\n*Step 3 (1 mark):* $n \\geq 971.44$, so $n = 972$.\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* $n \\geq \\tfrac{1.96^2 \\cdot 0.25}{0.0009}$.\n\n*Step 2 (1 mark):* $n \\geq 1067.11$, so $n = 1068$.\n\n**f. (1 mark)**\n\n*Step 1 (1 mark):* The conservative choice guarantees the desired margin of error regardless of the true $p$ (maximising $p(1 - p)$ at $p = 0.5$).\n\n**g. (2 marks)**\n\n*Step 1 (1 mark):* SE $= \\sqrt{0.33 \\cdot 0.67 / 900} \\approx 0.01568$.\n\n*Step 2 (1 mark):* Margin $= 1.96 \\cdot 0.01568 \\approx 0.0307$, so CI $\\approx (0.299, 0.361)$.\n\n**h. (2 marks)**\n\n*Step 1 (1 mark):* First CI half-width $\\approx 0.0935$; second half-width $\\approx 0.0307$.\n\n*Step 2 (1 mark):* The second CI is much narrower (about $1/3$) due to the larger sample size (factor $9$, so SE $\\div 3$).", subtopicSlugs: S },
  ];
  writeQset(OUT("sample-proportions-and-sampling"), { mcq, shortAnswer, extendedResponse });
}
